```typescript
import React, { useState, useEffect, useRef } from 'react';
import { Gemini } from 'gemini-api';

interface AIAudioPlayerProps {
  isPlaying: boolean;
  onAudioReady: (audioUrl: string) => void;
  onPlay: () => void;
  onPause: () => void;
  onStop: () => void;
}

const AIAudioPlayer: React.FC<AIAudioPlayerProps> = ({ isPlaying, onAudioReady, onPlay, onPause, onStop }) => {
  const [prompt, setPrompt] = useState<string>('');
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.play().then(() => {
          // Playback started
        }).catch((error) => {
          console.error("Playback error:", error);
        });
      } else {
        audioRef.current.pause();
      }
    }
  }, [isPlaying]);

  const generateAudio = async () => {
    if (!prompt.trim()) {
      alert("Please enter a prompt.");
      return;
    }

    setIsLoading(true);
    setAudioUrl(null); // Clear previous audio
    try {
      // Replace with your actual Gemini API call
      const gemini = new Gemini('YOUR_API_KEY');
      const response = await gemini.generateAudio(prompt, { model: 'gemini-2.5-flash-preview-tts', voice: 'en-US-Neural2-A' });

      if (response && response.audioUrl) {
        setAudioUrl(response.audioUrl);
        onAudioReady(response.audioUrl);
      } else {
        throw new Error('Failed to generate audio.');
      }
    } catch (error:any) {
      console.error('Error generating audio:', error.message);
      alert('Error generating audio. Please check the console.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleStop = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
    }
    onStop();
  };

  return (
    <div>
      <div>
        <input
          type="text"
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="Enter your prompt..."
        />
        <button onClick={generateAudio} disabled={isLoading}>
          {isLoading ? 'Generating...' : 'Generate Audio'}
        </button>
      </div>

      {audioUrl && (
        <div>
          <audio ref={audioRef} src={audioUrl} onEnded={onStop}>
            Your browser does not support the audio element.
          </audio>
          <button onClick={onPlay} disabled={isPlaying || isLoading}>Play</button>
          <button onClick={onPause} disabled={!isPlaying || isLoading}>Pause</button>
          <button onClick={handleStop} disabled={!isPlaying && !audioUrl || isLoading}>Stop</button>
        </div>
      )}
    </div>
  );
};

export default AIAudioPlayer;
```

