import React, { useState, useEffect, useMemo } from 'react';
import { PluginContainer } from '../shared/PluginContainer';
import { Knob } from '../shared/Knob';
import { Waveform } from '../shared/Waveform';
import { MixxDelaySettings, PluginComponentProps, AudioSignal, GlobalSettings } from '../../types';
import { PrimeBrainStub } from '../../lib/PrimeBrainStub';
import { mapRange } from '../../lib/utils';
import { VstBridge, VisualizerData } from '../../vst/VstBridge';
import { useVstBridge } from '../../vst/useVstBridge';

// --- VST Architecture ---

interface EchoData {
    key: number;
    opacity: number;
    animationName: string;
    animationDuration: number;
    animationDelay: number;
    color: string;
}

interface DelayVisualizerData extends VisualizerData {
    isFlashing: boolean;
    echos: EchoData[];
    mainColor: string;
}

class MixxDelayVstBridge extends VstBridge<MixxDelaySettings> {
    private lastThrowTime: number = 0;
    private isFlashing: boolean = false;
    private flashTimeout: any = null;

    constructor(initialSettings: MixxDelaySettings) {
        super(initialSettings);
    }

    public dspProcess(
        audioSignal: AudioSignal,
        width: number,
        height: number,
        globalSettings: GlobalSettings,
        extraData?: Record<string, any>
    ): DelayVisualizerData {
        const { time, feedback, throwIntuition, mix } = this.settings;
        const now = Date.now();
        const mood = extraData?.mood || 'Neutral';

        // Simulate "Throw" logic
        if (now - this.lastThrowTime > 2000 && Math.random() < throwIntuition / 100 * 0.1) {
            this.lastThrowTime = now;
            this.isFlashing = true;
            if (this.flashTimeout) clearTimeout(this.flashTimeout);
            this.flashTimeout = setTimeout(() => { this.isFlashing = false; }, 200);
        }

        const animationSpeedMultiplier = mapRange(globalSettings.animationIntensity, 0, 100, 1.5, 0.5);
        const numRepeats = globalSettings.visualizerComplexity === 'low' ? 4 : 8;

        // Dynamic Hue based on Mood
        const moodHueMap: Record<string, number> = {
            'Warm': 30, 'Bright': 60, 'Dark': 260, 'Energetic': 300, 'Neutral': 320 
        };
        const baseHue = moodHueMap[mood as string] || 320;

        const echos: EchoData[] = [];

        for (let i = 0; i < numRepeats; i++) {
            const index = i + 1;
            const opacity = Math.pow(feedback / 100, index) * (mix / 100);
            if (opacity < 0.01) break;

            const isThrown = this.isFlashing && i < 2; // Only make first couple of echos "throw"
            const animationName = isThrown ? 'delay-throw-burst' : 'delay-fade-in';
            const animationDuration = (isThrown ? time * 0.8 : time) * animationSpeedMultiplier;
            const color = `hsl(${baseHue - index * 20}, 100%, ${80 - index * 5}%)`;

            echos.push({
                key: index,
                opacity,
                animationName,
                animationDuration,
                animationDelay: index * time * animationSpeedMultiplier,
                color,
            });
        }

        return {
            isFlashing: this.isFlashing,
            echos,
            mainColor: `hsl(${baseHue}, 90%, 70%)`
        };
    }
}


// --- UI Components ---

const Echo: React.FC<EchoData> = React.memo(({ opacity, animationName, animationDuration, animationDelay, color }) => {
    return (
        <div
            className="absolute inset-0 w-full h-full pointer-events-none"
            style={{
                animation: `${animationName} ${animationDuration}ms ${animationDelay}ms forwards`,
                '--echo-opacity': opacity,
            } as React.CSSProperties}
        >
            <Waveform
                id={`delay-echo-${animationDelay}`}
                color={color}
                path="M 0 50 C 50 10, 80 90, 150 50 S 250 80, 300 50 S 420 10, 500 50"
            />
        </div>
    );
});

export const MixxDelay: React.FC<PluginComponentProps<MixxDelaySettings>> = ({
  isDragging, isResizing, name, description, pluginState, setPluginState, isLearning, onMidiLearn, onClose, globalSettings, audioSignal, sessionContext
}) => {
    const { time, feedback, throwIntuition, mix, output } = pluginState;

    const { visualizerData } = useVstBridge(
        pluginState,
        audioSignal,
        globalSettings,
        (initialState) => new MixxDelayVstBridge(initialState),
        { mood: sessionContext.mood }
    );

    const memoizedEchos = useMemo(() => {
        return (visualizerData as DelayVisualizerData | null)?.echos.map(echoData => <Echo key={echoData.key} {...echoData} />);
    }, [visualizerData]);


    const handleValueChange = (param: keyof MixxDelaySettings, value: number) => {
        setPluginState(prevState => ({ ...prevState, [param]: value }));
        PrimeBrainStub.sendEvent('parameter_change', { plugin: 'mixx-delay', parameter: param, value });
    };

    const isFlashing = (visualizerData as DelayVisualizerData | null)?.isFlashing ?? false;
    const mainColor = (visualizerData as DelayVisualizerData | null)?.mainColor ?? '#f472b6';

    // Pulse faster as time increases (1ms = slow, 2000ms = fast)
    const pulseDuration = Math.max(0.2, 2 - (time / 2000) * 1.8);

    return (
        <PluginContainer title={name} subtitle={description} isDragging={isDragging} isResizing={isResizing} onClose={onClose}>
            <style>{`
                @keyframes delay-fade-in {
                    from { opacity: 0; transform: scale(0.8); }
                    to { opacity: var(--echo-opacity); transform: scale(1); }
                }
                @keyframes delay-throw-burst {
                    0% { opacity: 0; transform: scale(0.5); filter: brightness(1) blur(5px); }
                    30% { opacity: var(--echo-opacity); transform: scale(1.2); filter: brightness(2) blur(0); }
                    100% { opacity: 0; transform: scale(1); filter: brightness(1) blur(2px); }
                }
                @keyframes knob-pulse-time {
                    0%, 100% { transform: scale(1); filter: brightness(1); }
                    50% { transform: scale(1.05); filter: brightness(1.3) drop-shadow(0 0 8px var(--glow-cyan)); }
                }
            `}</style>
            <div className="w-full h-full flex flex-col items-center justify-between gap-8 p-4">
                <div className="w-full h-32 relative flex items-center justify-center overflow-hidden">
                    <div className={`absolute inset-0 w-full h-full transition-all duration-100 ${isFlashing ? 'animate-[knob-value-flash_0.2s_ease-out]' : ''}`} style={{ opacity: mix / 100 }}>
                        <Waveform 
                            animated 
                            id="delay-main" 
                            color={mainColor} 
                            path="M 0 50 C 50 10, 80 90, 150 50 S 250 80, 300 50 S 420 10, 500 50" 
                            animationDuration={`${time}ms`}
                        />
                    </div>
                    {memoizedEchos}
                </div>

                <div className="flex w-full justify-around items-center">
                    <div style={{ animation: `knob-pulse-time ${pulseDuration}s infinite ease-in-out` }}>
                        <Knob label="Time" value={time} setValue={(v) => handleValueChange('time', v)} min={1} max={2000} step={1} paramName="time" isLearning={isLearning('time')} onMidiLearn={onMidiLearn} />
                    </div>
                    <Knob label="Feedback" value={feedback} setValue={(v) => handleValueChange('feedback', v)} paramName="feedback" isLearning={isLearning('feedback')} onMidiLearn={onMidiLearn} />
                    <Knob label="Throw" value={throwIntuition} setValue={(v) => handleValueChange('throwIntuition', v)} paramName="throwIntuition" isLearning={isLearning('throwIntuition')} onMidiLearn={onMidiLearn} />
                    <Knob label="Mix" value={mix} setValue={(v) => handleValueChange('mix', v)} paramName="mix" isLearning={isLearning('mix')} onMidiLearn={onMidiLearn} />
                    <Knob label="Output" value={output} setValue={(v) => handleValueChange('output', v)} paramName="output" isLearning={isLearning('output')} onMidiLearn={onMidiLearn} />
                </div>
            </div>
        </PluginContainer>
    );
};

import React, { useMemo } from 'react';
import { PluginContainer } from '../shared/PluginContainer';
import { Knob } from '../shared/Knob';
import { MixxVerbSettings, PluginComponentProps, AudioSignal, GlobalSettings } from '../../types';
import { PrimeBrainStub } from '../../lib/PrimeBrainStub';
import { mapRange } from '../../lib/utils';
import { VstBridge, VisualizerData } from '../../vst/VstBridge';
import { useVstBridge } from '../../vst/useVstBridge';

// --- VST Architecture ---

interface Particle {
    id: number;
    angle: number;
    distance: number;
    size: number;
    opacity: number;
    duration: number;
    delay: number;
    color: string;
    spawnTime: number;
}

interface VerbVisualizerData extends VisualizerData {
    particles: Particle[];
    isPulsing: boolean;
    decayCurve: string;
}

class MixxVerbVstBridge extends VstBridge<MixxVerbSettings> {
    private particles: Particle[] = [];
    private particleIdCounter: number = 0;
    private lastBurstTime: number = 0;
    private isPulsing: boolean = false;
    private pulseTimeout: any = null;

    constructor(initialSettings: MixxVerbSettings) {
        super(initialSettings);
    }

    public dspProcess(
        audioSignal: AudioSignal,
        width: number,
        height: number,
        globalSettings: GlobalSettings
    ): VerbVisualizerData {
        const { size, predelay, mix } = this.settings;
        const now = audioSignal.time;

        // Audio-reactive trigger logic
        // Trigger on transients, or occasionally during loud segments, or fallback timer
        const isTransient = audioSignal.transients;
        const isLoud = audioSignal.level > 20;
        const timeSinceLast = now - this.lastBurstTime;

        const shouldTrigger = (isTransient && timeSinceLast > 0.15) || 
                              (isLoud && Math.random() > 0.92 && timeSinceLast > 0.3) ||
                              (timeSinceLast > 3); // Keep alive pulse

        if (shouldTrigger) {
            this.lastBurstTime = now;

            const baseParticleCount = (globalSettings.visualizerComplexity === 'low' ? 3 : 8);
            const particleDensityMultiplier = (globalSettings.visualizerComplexity === 'low' ? 10 : 25);
            const normalizedMix = mix / 100;

            if (normalizedMix > 0.01) {
                this.isPulsing = true;
                if (this.pulseTimeout) clearTimeout(this.pulseTimeout);
                this.pulseTimeout = setTimeout(() => { this.isPulsing = false; }, predelay + 300);

                // Scale particle count by audio level for more dynamic feel
                const levelScale = Math.max(0.5, audioSignal.level / 80);
                const particleCount = Math.round((baseParticleCount + (size / 100 * particleDensityMultiplier)) * levelScale);

                const newParticles: Particle[] = Array.from({ length: particleCount }).map(() => {
                    const lifetime = 1.5 + (size / 100) * 4; // Longer tails for larger size
                    const perspective = Math.random();
                    this.particleIdCounter++;

                    // Color shifts based on size (Blue/Cyan for small, Pink/Purple for large/long)
                    const hue = size > 60 ? 280 + Math.random() * 60 : 180 + Math.random() * 60;

                    return {
                        id: this.particleIdCounter,
                        angle: Math.random() * 360,
                        distance: 20 + Math.random() * 50 * perspective * (1 + size / 100),
                        size: (1 + perspective * 3) * (2 + Math.random() * 4),
                        opacity: (0.3 + perspective * 0.7) * normalizedMix * (audioSignal.level/100),
                        duration: lifetime * (0.8 + Math.random() * 0.4),
                        delay: predelay / 1000, // ms to s
                        color: `hsla(${hue}, 80%, 70%, 0.8)`,
                        spawnTime: now,
                    };
                });
                this.particles.push(...newParticles);
                if(this.particles.length > 200) this.particles.splice(0, this.particles.length - 200);
            }
        }

        // Particle lifetime management
        this.particles = this.particles.filter(p => now < p.spawnTime + p.delay + p.duration);

        // Generate decay curve path for background visualizer
        const decayPoints = [];
        const steps = 40;
        // Simple exponential decay model simulation
        // Size 0 -> Fast decay (low tau), Size 100 -> Slow decay (high tau)
        const tau = 0.5 + (size / 100) * 2.0; 

        for(let i=0; i<=steps; i++) {
            const t = i/steps; // 0 to 1
            const amp = Math.exp(-t * 5 / tau); 
            const x = t * 100;
            const y = (1 - amp) * 100; // 0 is top (max amp), 100 is bottom (0 amp)
            decayPoints.push(`${x.toFixed(1)},${y.toFixed(1)}`);
        }
        const decayCurve = `M 0,100 L 0,0 L ${decayPoints.join(' L ')} L 100,100 Z`;

        return {
            particles: [...this.particles],
            isPulsing: this.isPulsing,
            decayCurve,
        };
    }
}

// --- UI Components ---

const ReverbSpaceVisualizer: React.FC<{ visualizerData: VerbVisualizerData | null, globalSettings: GlobalSettings }> = 
({ visualizerData, globalSettings }) => {

    const animationSpeedMultiplier = mapRange(globalSettings.animationIntensity, 0, 100, 1.5, 0.5);

    const particles = visualizerData?.particles ?? [];
    const isPulsing = visualizerData?.isPulsing ?? false;
    const predelay = visualizerData && visualizerData.particles.length > 0 ? (visualizerData.particles[visualizerData.particles.length-1]?.delay ?? 0) * 1000 : 0;
    const decayCurve = visualizerData?.decayCurve;

    return (
        <div className="relative w-full h-full flex items-center justify-center overflow-hidden [perspective:800px]">
            {/* Background Decay Curve */}
            {decayCurve && (
                <svg className="absolute inset-0 w-full h-full opacity-20 pointer-events-none" preserveAspectRatio="none" viewBox="0 0 100 100">
                    <defs>
                        <linearGradient id="verb-decay-grad" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="0%" stopColor="#22d3ee" stopOpacity="0.3" />
                            <stop offset="100%" stopColor="#22d3ee" stopOpacity="0" />
                        </linearGradient>
                    </defs>
                    <path d={decayCurve} fill="url(#verb-decay-grad)" stroke="#22d3ee" strokeWidth="0.5" />
                </svg>
            )}

            {isPulsing && (
                <div 
                    className="absolute w-8 h-8 rounded-full bg-cyan-400/50"
                    style={{
                        animation: `reverb-core-pulse ${300}ms ease-out`,
                        opacity: 0,
                        filter: 'blur(4px)'
                    }}
                />
            )}

            {particles.map((p: Particle) => (
                <div
                    key={p.id}
                    className="absolute rounded-full"
                    style={{
                        width: p.size,
                        height: p.size,
                        top: '50%',
                        left: '50%',
                        backgroundColor: p.color,
                        boxShadow: `0 0 ${p.size}px ${p.color}`,
                        opacity: 0,
                        animation: `reverb-particle ${p.duration * animationSpeedMultiplier}s ${p.delay}s forwards ease-out`,
                        '--angle': `${p.angle}deg`,
                        '--distance': `${p.distance}%`,
                        '--opacity': p.opacity
                    } as React.CSSProperties}
                />
            ))}
             <style>{`
                @keyframes reverb-particle {
                    0% { transform: translate(-50%, -50%) rotate(var(--angle)) translateY(0) scale(0); opacity: var(--opacity); }
                    10% { opacity: var(--opacity); }
                    100% { transform: translate(-50%, -50%) rotate(var(--angle)) translateY(var(--distance)) scale(0); opacity: 0; }
                }
                @keyframes reverb-core-pulse {
                    0% { transform: translate(-50%, -50%) scale(0.5); opacity: 0.8; }
                    100% { transform: translate(-50%, -50%) scale(2); opacity: 0; }
                }
            `}</style>
        </div>
    );
};


