  (acc as any)[key as PluginKey] = { 
    x: window.innerWidth / 2 - (INITIAL_PLUGIN_SIZES[key as PluginKey].width / 2), 
    y: window.innerHeight / 2 - (INITIAL_PLUGIN_SIZES[key as PluginKey].height / 2) 
  };
  return acc;
}, {} as PluginPositions);

