import { useState, useEffect, useRef, useCallback } from 'react';
import { AudioSignal } from '../types';

// Audio decoding functions from the Gemini API guide
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}


export const useSimulatedAudio = () => {
  const [audioSignal, setAudioSignal] = useState<AudioSignal>({
    level: 0,
    peak: 0,
    transients: false,
    waveform: new Float32Array(512).fill(0),
    time: 0,
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [sourceType, setSourceType] = useState<'simulated' | 'file' | 'mic'>('simulated');
  const [isMicActive, setIsMicActive] = useState(false);

  const animationFrameId = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceNodeRef = useRef<AudioNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const micStreamRef = useRef<MediaStream | null>(null);
  const audioTimeRef = useRef(0);
  const currentBufferRef = useRef<AudioBuffer | null>(null);

  // Initialize Audio Context and Analyser
  const initAudioContext = useCallback(() => {
    if (audioContextRef.current) return;
    try {
      const context = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioContextRef.current = context;
      analyserRef.current = context.createAnalyser();
      analyserRef.current.fftSize = 1024;
      analyserRef.current.smoothingTimeConstant = 0.8;

      gainNodeRef.current = context.createGain();
      gainNodeRef.current.gain.setValueAtTime(1.0, context.currentTime);
      gainNodeRef.current.connect(analyserRef.current);

      // Default: Connect analyser to destination (speakers)
      // For mic, we will disconnect this to prevent feedback
      analyserRef.current.connect(context.destination);
    } catch (e) {
      console.error("Web Audio API not supported", e);
    }
  }, []);

  const stop = useCallback(() => {
    if (sourceNodeRef.current) {
      if (sourceNodeRef.current instanceof AudioBufferSourceNode || sourceNodeRef.current instanceof OscillatorNode) {
        try {
            (sourceNodeRef.current as any).stop();
        } catch(e) {
            // ignore if already stopped
        }
      }
      sourceNodeRef.current.disconnect();
      sourceNodeRef.current = null;
    }

    // Stop Mic Stream if active but switching modes
    if (sourceType !== 'mic' && micStreamRef.current) {
        micStreamRef.current.getTracks().forEach(track => track.stop());
        micStreamRef.current = null;
        setIsMicActive(false);
    }

    setIsPlaying(false);
  }, [sourceType]);

  const playDefaultTone = useCallback(() => {
    if (!audioContextRef.current || !gainNodeRef.current || !analyserRef.current) return;
    stop();
    setSourceType('simulated');

    // Ensure output is connected for oscillator
    try { analyserRef.current.connect(audioContextRef.current.destination); } catch(e) {}

    const oscillator = audioContextRef.current.createOscillator();
    oscillator.type = 'sine';
    oscillator.frequency.setValueAtTime(150, audioContextRef.current.currentTime);
    oscillator.connect(gainNodeRef.current);
    oscillator.start();
    sourceNodeRef.current = oscillator;
    setIsPlaying(true);
  }, [stop]);

  const handleFileDrop = useCallback(async (file: File) => {
      if (!audioContextRef.current) initAudioContext();
      if (!audioContextRef.current) return;

      try {
          const arrayBuffer = await file.arrayBuffer();
          const audioBuffer = await audioContextRef.current.decodeAudioData(arrayBuffer);
          currentBufferRef.current = audioBuffer;
          setSourceType('file');

          // Trigger playback
          play();
      } catch (err) {
          console.error("Error decoding audio file:", err);
      }
  }, [initAudioContext]); // play is defined below, so we can't depend on it easily without hoist or ref. We'll use a useEffect or direct call if we rearrange.
  // Actually, 'play' depends on 'stop', and 'stop' depends on 'sourceType'. Circular dependency hell.
  // Let's implement play buffer logic inside handleFileDrop for simplicity or ensure play is stable.

  // Main playback control
  const play = useCallback(() => {
    if (!audioContextRef.current || !gainNodeRef.current || !analyserRef.current) return;

    // Resume context if suspended
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }

    if (sourceType === 'file' && currentBufferRef.current) {
        stop();
        // Ensure output connected
        try { analyserRef.current.connect(audioContextRef.current.destination); } catch(e) {}

        const bufferSource = audioContextRef.current.createBufferSource();
        bufferSource.buffer = currentBufferRef.current;
        bufferSource.connect(gainNodeRef.current);
        bufferSource.onended = () => {
            setIsPlaying(false);
            // Optional: Loop or return to default
        };
        bufferSource.start(0);
        sourceNodeRef.current = bufferSource;
        setIsPlaying(true);
    } else if (sourceType === 'simulated') {
        playDefaultTone();
    } else if (sourceType === 'mic') {
        // Mic is already running if active
        setIsPlaying(true);
    }
  }, [stop, playDefaultTone, sourceType]);

  // We need to re-bind handleFileDrop to call the updated 'play'
  const handleFileDropWithPlay = useCallback(async (file: File) => {
      await handleFileDrop(file); // loads buffer and sets type
      // We need to wait for state update or force it.
      // simpler: just call play logic directly here for the buffer
      if (audioContextRef.current && currentBufferRef.current) {
           // We manually trigger the 'file' play logic here to avoid state race conditions
           if (sourceNodeRef.current) {
                try { (sourceNodeRef.current as any).stop(); } catch(e) {}
                sourceNodeRef.current.disconnect();
           }
           // Connect output
           try { analyserRef.current?.connect(audioContextRef.current.destination); } catch(e) {}

           const bufferSource = audioContextRef.current.createBufferSource();
           bufferSource.buffer = currentBufferRef.current;
           bufferSource.connect(gainNodeRef.current!);
           bufferSource.start(0);
           sourceNodeRef.current = bufferSource;
           setIsPlaying(true);
      }
  }, [handleFileDrop]);


  const toggleMic = useCallback(async () => {
      if (!audioContextRef.current) initAudioContext();
      const ctx = audioContextRef.current!;

      if (isMicActive) {
          // Stop Mic
          if (micStreamRef.current) {
              micStreamRef.current.getTracks().forEach(track => track.stop());
              micStreamRef.current = null;
          }
          setIsMicActive(false);
          setSourceType('simulated');
          playDefaultTone();
      } else {
          // Start Mic
          try {
              stop(); // Stop other sources

              // Disconnect output to prevent feedback loop!
              try { analyserRef.current?.disconnect(ctx.destination); } catch(e) {}

              const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
              micStreamRef.current = stream;

              const source = ctx.createMediaStreamSource(stream);
              source.connect(analyserRef.current!);

              sourceNodeRef.current = source;
              setIsMicActive(true);
              setSourceType('mic');
              setIsPlaying(true);
          } catch (err) {
              console.error("Microphone access denied or error:", err);
              alert("Could not access microphone. Please check permissions.");
          }
      }
  }, [isMicActive, initAudioContext, stop, playDefaultTone]);


  // Analysis Loop
  useEffect(() => {
    initAudioContext();
    if (sourceType === 'simulated' && !isPlaying) {
        playDefaultTone();
    }

    const analyser = analyserRef.current;
    if (!analyser) return () => {};

    const dataArray = new Uint8Array(analyser.frequencyBinCount);
    const waveformArray = new Float32Array(analyser.fftSize);

    const animate = () => {
      audioTimeRef.current = audioContextRef.current?.currentTime ?? audioTimeRef.current;
      analyser.getByteFrequencyData(dataArray);
      analyser.getFloatTimeDomainData(waveformArray);

      // Calculate levels
      let sum = 0;
      let peak = 0;
      for (let i = 0; i < dataArray.length; i++) {
          const val = dataArray[i];
          sum += val;
          if (val > peak) peak = val;
      }
      const avg = sum / dataArray.length;
      const currentLevel = (avg / 255) * 100 * 1.5; // Boost slightly

      // Basic transient detection
      const currentTransients = (Math.random() > 0.95 && currentLevel > 40) || (peak > 240 && Math.random() > 0.8);

      setAudioSignal({
        level: Math.min(100, currentLevel),
        peak: peak,
        transients: currentTransients,
        waveform: waveformArray,
        time: audioTimeRef.current,
      });

      animationFrameId.current = requestAnimationFrame(animate);
    };

    animationFrameId.current = requestAnimationFrame(animate);

    return () => {
      if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
      // Don't close context here, just stop loop
    };
  }, [initAudioContext, playDefaultTone]); // Intentionally minimal deps for loop

  // Load AI Audio Helper
  const loadAudio = useCallback(async (base64: string) => {
    if (!audioContextRef.current) return null;
    stop();
    try {
      const decodedBytes = decode(base64);
      const audioBuffer = await decodeAudioData(decodedBytes, audioContextRef.current, 24000, 1);
      currentBufferRef.current = audioBuffer;
      setSourceType('file'); // Treat TTS as file
      return audioBuffer;
    } catch (e) {
      console.error("Failed to decode audio data", e);
      return null;
    }
  }, [stop]);

  const pause = useCallback(() => {
    if (!audioContextRef.current) return;
    if (audioContextRef.current.state === 'running') {
      audioContextRef.current.suspend();
      setIsPlaying(false);
    }
  }, []);

  return { 
      audioSignal, 
      isPlaying, 
      loadAudio, 
      play, 
      pause, 
      stopAndPlayDefault: playDefaultTone,
      handleFileDrop: handleFileDropWithPlay,
      toggleMic,
      isMicActive,
      sourceType
  };
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality } from "@google/genai";
import { MusicIcon, PlayIcon, PauseIcon, LoaderIcon, MicIcon, MicOffIcon } from './shared/Icons';

interface AIAudioPlayerProps {
  isPlaying: boolean;
  onAudioReady: (base64Audio: string) => void;
  onPlay: () => void;
  onPause: () => void;
  onStop: () => void;
  toggleMic: () => void;
  isMicActive: boolean;
}

export const AIAudioPlayer: React.FC<AIAudioPlayerProps> = ({ isPlaying, onAudioReady, onPlay, onPause, onStop, toggleMic, isMicActive }) => {
  const [prompt, setPrompt] = useState('System online. Ready for input.');
  const [isLoading, setIsLoading] = useState(false);
  const [showInput, setShowInput] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (showInput && inputRef.current) {
        inputRef.current.focus();
    }
  }, [showInput]);

  const handleGenerate = async () => {
    if (!prompt.trim() || isLoading) return;
    setIsLoading(true);
    onStop(); // Stop current playback

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: prompt }] }],
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: {
                  prebuiltVoiceConfig: { voiceName: 'Kore' },
                },
            },
        }
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
          onAudioReady(base64Audio);
          setShowInput(false);
      }
    } catch (e) {
      console.error("TTS generation failed", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
          handleGenerate();
      } else if (e.key === 'Escape') {
          setShowInput(false);
      }
  };

  return (
    <div className="flex items-center gap-2">
        {showInput ? (
            <div className="flex items-center bg-black/40 rounded-full border border-cyan-500/50 px-2 py-1 transition-all">
                <input 
                    ref={inputRef}
                    type="text" 
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    onKeyDown={handleKeyDown}
                    disabled={isLoading}
                    className="bg-transparent border-none outline-none text-xs text-white w-48 placeholder-white/30"
                    placeholder="Type to speak..."
                />
                <button 
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className="ml-2 text-cyan-400 hover:text-white"
                >
                    {isLoading ? <LoaderIcon className="w-3 h-3 animate-spin" /> : <span className="text-xs font-bold">GO</span>}
                </button>
            </div>
        ) : (
            <button 
                onClick={() => setShowInput(true)} 
                className="p-1.5 rounded-full text-cyan-400 hover:bg-cyan-400/20 hover:text-white transition-all group"
                title="AI Text-to-Speech"
            >
                <MusicIcon className="w-4 h-4 transition-transform group-hover:scale-110" />
            </button>
        )}

        <div className="w-px h-4 bg-white/10 mx-1" />

        <button 
            onClick={toggleMic}
            className={`p-1.5 rounded-full transition-all group ${isMicActive ? 'text-red-500 bg-red-500/10 shadow-[0_0_10px_rgba(239,68,68,0.5)]' : 'text-white/80 hover:bg-white/10 hover:text-white'}`}
            title={isMicActive ? "Disable Microphone" : "Enable Microphone Input"}
        >
            {isMicActive ? <MicOffIcon className="w-4 h-4" /> : <MicIcon className="w-4 h-4" />}
        </button>

        <button 
            onClick={isPlaying ? onPause : onPlay}
            className="p-1.5 rounded-full text-white/80 hover:bg-white/10 hover:text-white transition-all"
            title={isPlaying ? "Pause" : "Play"}
        >
            {isPlaying ? <PauseIcon className="w-4 h-4" /> : <PlayIcon className="w-4 h-4" />}
        </button>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { findPlugin, INITIAL_PLUGIN_SIZES, INITIAL_PLUGIN_POSITIONS, INITIAL_PLUGIN_STATES, PluginKey, TierName } from './constants'; 
import { MixxClubLogo, HaloIcon, SaveIcon, SettingsIcon, LinkIcon, GridIcon, ResetIcon, LightbulbIcon, UploadIcon } from './components/shared/Icons';
import { HaloSchematic } from './components/HaloSchematic';
import { SessionContext, PluginPositions, PluginSize, PluginSizes, PluginPosition, SpecificPluginSettingsMap, PluginStates, MidiMappingMap, PluginComponentProps, Preset, PanelType, SidechainLink, AudioSignal, GlobalSettings } from './types'; 
import { ResizableContainer } from './components/shared/ResizableContainer';
import { motion, AnimatePresence } from 'framer-motion';
import { useMidi } from './hooks/useMidi';
import { isControlChange } from './lib/midi';
import { usePresets } from './hooks/usePresets';
import { RoutingView } from './components/RoutingView';
import { PluginBrowser } from './components/PluginBrowser';
import { SidePanel } from './components/SidePanel';
import { PrimeBrainStub } from './lib/PrimeBrainStub';
import { useSimulatedAudio } from './hooks/useSimulatedAudio';
import { SettingsPanel } from './components/SettingsPanel'; 
import { mapRange } from './lib/utils';
import { useGlobalSettings } from './hooks/useGlobalSettings';
import { AIAudioPlayer } from './components/AIAudioPlayer';
import { AmbientBackground } from './components/shared/AmbientBackground';

const App: React.FC = () => {
  const [activePlugin, setActivePlugin] = useState<PluginKey | null>(null); 
  const [view, setView] = useState<'plugin' | 'halo'>('plugin');
  const [sessionContext, setSessionContext] = useState<SessionContext>({ mood: 'Neutral' });
  const [pluginStates, setPluginStates] = useState<PluginStates>(INITIAL_PLUGIN_STATES); 
  const [pluginSizes, setPluginSizes] = useState<PluginSizes>(INITIAL_PLUGIN_SIZES);
  const [pluginPositions, setPluginPositions] = useState<PluginPositions>(INITIAL_PLUGIN_POSITIONS);
  const [activePluginZIndex, setActivePluginZIndex] = useState(10); 
  const [activePanel, setActivePanel] = useState<PanelType>(null);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isDraggingFile, setIsDraggingFile] = useState(false); // New state for file drag
  const transitionStartRef = useRef<number | null>(null);

  const { 
      audioSignal, isPlaying, loadAudio, play, pause, stopAndPlayDefault, 
      handleFileDrop, toggleMic, isMicActive 
  } = useSimulatedAudio();

  // Global Settings State using the new persistence hook
  const { globalSettings, setGlobalSettings } = useGlobalSettings();

  // Calculate dynamic transition duration based on animationIntensity
  const dynamicTransitionDuration = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 0.2);

  // MIDI State
  const { inputs: midiInputs, selectedInputId, setSelectedInputId, attachMidiListener } = useMidi();
  const [midiMappings, setMidiMappings] = useState<MidiMappingMap>({});
  const [midiLearnTarget, setMidiLearnTarget] = useState<{ pluginKey: PluginKey, paramName: string, min: number, max: number } | null>(null);

  // Preset State
  const { presets, savePreset, deletePreset } = usePresets();

  // Routing State
  const [sidechainLinks, setSidechainLinks] = useState<SidechainLink[]>([]);

  // Drag and Drop Handlers
  const handleDragOver = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingFile(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      // Only set false if leaving the window (relatedTarget is null)
      if (!e.relatedTarget) {
          setIsDraggingFile(false);
      }
  }, []);

  const handleDrop = useCallback(async (e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingFile(false);

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
          const file = e.dataTransfer.files[0];
          if (file.type.startsWith('audio/')) {
              await handleFileDrop(file);
              PrimeBrainStub.sendEvent('audio_file_dropped', { name: file.name });
          } else {
              alert("Please drop a valid audio file.");
          }
      }
  }, [handleFileDrop]);

  const handleSelectPlugin = (pluginKey: PluginKey) => {
      setIsTransitioning(true);
      transitionStartRef.current = performance.now();
      setActivePlugin(pluginKey);
      PrimeBrainStub.sendEvent('plugin_activated', { pluginKey, name: findPlugin(pluginKey).name });
  };

  const handleClosePlugin = () => {
      setIsTransitioning(true);
      transitionStartRef.current = performance.now();
      setActivePlugin(null);
  }

  // Effect to manage `isTransitioning` for a set duration after `handleSelectPlugin` or `handleClosePlugin`
  useEffect(() => {
      if (isTransitioning) {
          const timer = setTimeout(() => {
              setIsTransitioning(false);
          }, dynamicTransitionDuration * 1000 + 100); // Allow some time for the layout animation to complete
          return () => clearTimeout(timer);
      }
  }, [isTransitioning, dynamicTransitionDuration]);

  const handlePluginStateChange = useCallback(<K extends PluginKey>(
    pluginId: K, 
    newState: Partial<SpecificPluginSettingsMap[K]> | ((prevState: SpecificPluginSettingsMap[K]) => Partial<SpecificPluginSettingsMap[K]>)
  ) => {
    setPluginStates(prevStates => {
      const currentPluginState = prevStates[pluginId];
      let updatedPartialState: Partial<SpecificPluginSettingsMap[K]>;

      if (typeof newState === 'function') {
        updatedPartialState = (newState as Function)(currentPluginState);
      } else {
        updatedPartialState = newState;
      }

      return {
        ...prevStates,
        [pluginId]: {
          ...currentPluginState,
          ...updatedPartialState
        } as SpecificPluginSettingsMap[K]
      };
    });
  }, []);

  const handleGlobalSettingsChange = useCallback((newSettings: Partial<GlobalSettings>) => {
      setGlobalSettings(newSettings); // This now uses the setter from the hook, which handles persistence
      PrimeBrainStub.sendEvent('global_settings_change', newSettings);
  }, [setGlobalSettings]);

  const handleAudioReady = useCallback(async (base64Audio: string) => {
    await loadAudio(base64Audio);
    play(); // Auto-play when ready
  }, [loadAudio, play]);


  const handleMidiMessage = useCallback((message: MIDIMessageEvent) => {
    if (!isControlChange(message) || !message.target) return;

    const [, cc, value] = message.data;
    const deviceId = (message.target as any).id;
    const mappingKey = `${deviceId}-${cc}`;

    if (midiLearnTarget) {
        const newMapping = {
            pluginKey: midiLearnTarget.pluginKey,
            paramName: midiLearnTarget.paramName,
            min: midiLearnTarget.min,
            max: midiLearnTarget.max,
        };
        setMidiMappings(prev => ({ ...prev, [mappingKey]: newMapping }));
        PrimeBrainStub.sendEvent('midi_mapped', { deviceId, cc, ...newMapping });
        setMidiLearnTarget(null);
        return;
    }

    const mapping = midiMappings[mappingKey];
    if (mapping) {
        const { pluginKey, paramName, min, max } = mapping;
        const scaledValue = min + (value / 127) * (max - min);
        handlePluginStateChange(pluginKey as PluginKey, (prevState: any) => ({
            ...prevState,
            [paramName]: scaledValue,
        }));
    }
  }, [midiLearnTarget, midiMappings, handlePluginStateChange]);

  useEffect(() => {
    const cleanup = attachMidiListener(handleMidiMessage);
    return cleanup;
  }, [attachMidiListener, handleMidiMessage]);

  const handleMidiLearnStart = useCallback((pluginKey: PluginKey, paramName: string, min: number, max: number) => {
    setMidiLearnTarget(prev => {
        if (prev && prev.pluginKey === pluginKey && prev.paramName === paramName) {
            return null;
        }
        PrimeBrainStub.sendEvent('midi_learn_started', { pluginKey, paramName });
        return { pluginKey, paramName, min, max };
    });
  }, []);

  const handleSavePreset = () => {
    const name = window.prompt("Enter a name for your preset:");
    if (name) {
      const isOverwriting = presets.some(p => p.name === name);
      if (isOverwriting) {
        if (!window.confirm(`A preset named "${name}" already exists. Overwrite it?`)) {
          return;
        }
      }
      savePreset(name, pluginStates);
      PrimeBrainStub.sendEvent('preset_saved', { name });
    }
  };

  const handleLoadPreset = (name: string) => {
    const preset = presets.find(p => p.name === name);
    if (preset) {
      setPluginStates(preset.states);
      PrimeBrainStub.sendEvent('preset_loaded', { name });
    }
  };

  const handleDeletePreset = (name: string) => {
    if (window.confirm(`Are you sure you want to delete the preset "${name}"?`)) {
      deletePreset(name);
      PrimeBrainStub.sendEvent('preset_deleted', { name });
    }
  };

  const handleAddLink = useCallback((newLink: SidechainLink) => {
    setSidechainLinks(prev => {
      if (prev.some(link => link.to === newLink.to)) return prev;
      PrimeBrainStub.sendEvent('sidechain_linked', newLink);
      return [...prev, newLink];
    });
  }, []);

  const handleRemoveLink = useCallback((linkToRemove: SidechainLink) => {
    setSidechainLinks(prev => prev.filter(link => !(link.from === linkToRemove.from && link.to === linkToRemove.to)));
    PrimeBrainStub.sendEvent('sidechain_unlinked', linkToRemove);
    const targetPluginKey = linkToRemove.to;
    const pluginInfo = findPlugin(targetPluginKey);
    if (pluginInfo.canBeSidechainTarget) {
      handlePluginStateChange(targetPluginKey, { sidechainActive: false } as any);
    }
  }, [handlePluginStateChange]);

  const handleResetSession = () => {
      if (window.confirm("Are you sure you want to reset your session? All settings will be lost.")) {
          localStorage.clear();
          PrimeBrainStub.sendEvent('session_reset', {});
          window.location.reload();
      }
  };

  const renderActivePlugin = () => {
    if (!activePlugin) return null;

    const pluginInfo = findPlugin(activePlugin);
    const ActivePluginComponent = pluginInfo.component as React.FC<PluginComponentProps<any>>;
    type CurrentPluginSettings = React.ComponentProps<typeof ActivePluginComponent>['pluginState'];

    const pluginProps = {
      name: pluginInfo.name,
      description: pluginInfo.description,
      sessionContext,
      setSessionContext: (newContext: SessionContext) => setSessionContext(newContext),
      pluginState: pluginStates[activePlugin] as CurrentPluginSettings, 
      setPluginState: (newState: Partial<CurrentPluginSettings> | ((prevState: CurrentPluginSettings) => Partial<CurrentPluginSettings>)) => handlePluginStateChange(activePlugin, newState as any),
      isLearning: (paramName: string) => midiLearnTarget?.pluginKey === activePlugin && midiLearnTarget?.paramName === paramName,
      onMidiLearn: (paramName: string, min: number, max: number) => handleMidiLearnStart(activePlugin, paramName, min, max),
      isSidechainTarget: sidechainLinks.some(link => link.to === activePlugin),
      audioSignal: audioSignal, // Pass the global audio signal here
      onClose: handleClosePlugin, // Pass the close handler to the plugin
      globalSettings: globalSettings, // Pass global settings to plugins
    };

    return (
       <ResizableContainer
        key={activePlugin}
        layoutId={activePlugin}
        initialSize={pluginSizes[activePlugin]}
        initialPosition={pluginPositions[activePlugin]}
        onResizeStop={(newSize) => setPluginSizes(prev => ({ ...prev, [activePlugin]: newSize }))}
        onDragStop={(newPosition) => setPluginPositions(prev => ({ ...prev, [activePlugin]: newPosition }))}
        onInteractionStart={() => setActivePluginZIndex(50)}
        onInteractionStop={() => setActivePluginZIndex(40)}
        zIndex={activePluginZIndex}
        onAnimationComplete={() => setIsTransitioning(false)}
        globalSettings={globalSettings} // Pass global settings
      >
        <ActivePluginComponent {...pluginProps} />
      </ResizableContainer>
    );
  };

  return (
    <div 
        className="text-white min-h-screen bg-[#0d1117] relative overflow-hidden"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
    >
      <AmbientBackground mood={sessionContext.mood} intensity={globalSettings.animationIntensity} />

      {/* File Drop Overlay */}
      <AnimatePresence>
          {isDraggingFile && (
              <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex flex-col items-center justify-center border-4 border-dashed border-cyan-500/50 pointer-events-none"
              >
                  <UploadIcon className="w-24 h-24 text-cyan-400 mb-4 animate-bounce" />
                  <h2 className="font-orbitron text-4xl font-bold text-white">DROP AUDIO TO LOAD</h2>
                  <p className="text-cyan-300 mt-2">Analyze and process your track</p>
              </motion.div>
          )}
      </AnimatePresence>

      <div className="relative flex flex-col h-screen z-10">
        <AnimatePresence>
          {activePlugin && (
            <motion.header 
              className="absolute top-0 left-0 right-0 flex items-center justify-between z-20 p-4"
              initial={{ y: -60, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: -60, opacity: 0 }}
              transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            >
                <div className="flex items-center gap-4">
                    <MixxClubLogo className="h-8 w-8" />
                    <h1 className="font-orbitron text-xl font-bold tracking-wider">MixxClub</h1>
                </div>

                <div className="flex items-center gap-2 p-2 rounded-full bg-black/30 backdrop-blur-md border border-white/20">
                    <AIAudioPlayer 
                        isPlaying={isPlaying}
                        onAudioReady={handleAudioReady}
                        onPlay={play}
                        onPause={pause}
                        onStop={stopAndPlayDefault}
                        toggleMic={toggleMic}
                        isMicActive={isMicActive}
                    />
                    <div className="w-px h-6 bg-white/20" />
                    <button onClick={handleClosePlugin} className="group p-2 text-white/60 hover:text-white transition-colors" title="Plugin Browser">
                        <GridIcon className="w-5 h-5 transition-all text-cyan-300 group-hover:drop-shadow-[0_0_3px_var(--glow-cyan)] icon-pulse-animated" />
                    </button>
                     <button onClick={() => setActivePanel('presets')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Presets">
                         <SaveIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel('settings')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Settings">
                         <SettingsIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel('routing')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Routing">
                         <LinkIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel(p => p === 'console' ? null : 'console')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="AI Console">
                         <LightbulbIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                      <button onClick={handleResetSession} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Reset Session">
                         <ResetIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button 
                        onClick={() => setView(view === 'plugin' ? 'halo' : 'plugin')}
                        className="p-2 rounded-full bg-white/10 text-cyan-300 hover:bg-cyan-400/20 hover:text-white transition-all duration-300 group hover:scale-105"
                        aria-label="Toggle Halo View"
                      >
                        <HaloIcon className="h-5 w-5 halo-icon-animated transition-all group-hover:drop-shadow-[0_0_4px_var(--glow-cyan)]" />
                     </button>
                </div>
            </motion.header>
          )}
        </AnimatePresence>

        <main className="flex-1 flex items-center justify-center transition-all duration-500">
          <AnimatePresence mode="wait">
            {view === 'halo' ? (
              <motion.div 
                key="halo" 
                initial={{opacity: 0}} 
                animate={{opacity: 1}} 
                exit={{opacity: 0}} 
                transition={{ duration: dynamicTransitionDuration, ease: 'easeInOut' }}
                className="w-full h-full"
              >
                <HaloSchematic 
                  setActivePlugin={(p: PluginKey) => { 
                    handleSelectPlugin(p); 
                    setView('plugin');
                  }} 
                  sessionContext={sessionContext}
                  pluginStates={pluginStates} 
                />
              </motion.div>
            ) : (
               activePlugin ? (
                  <div key="plugin-active" className="w-full h-full">{renderActivePlugin()}</div>
               ) : (
                  <PluginBrowser 
                    key="plugin-browser" 
                    onSelectPlugin={handleSelectPlugin} 
                    activePlugin={activePlugin}
                    isTransitioning={isTransitioning}
                    globalSettings={globalSettings} // Pass global settings
                  />
               )
            )}
          </AnimatePresence>
        </main>

        <AnimatePresence>
          {activePanel === 'routing' && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-[100]"
              transition={{ duration: dynamicTransitionDuration, ease: 'easeInOut' }}
            >
              <RoutingView 
                sidechainLinks={sidechainLinks}
                onAddLink={handleAddLink}
                onRemoveLink={handleRemoveLink}
                onClose={() => setActivePanel(null)}
              />
            </motion.div>
          )}
        </AnimatePresence>

        <SidePanel
            activePanel={activePanel}
            setActivePanel={setActivePanel}
            presets={presets}
            onSavePreset={handleSavePreset}
            onLoadPreset={handleLoadPreset}
            onDeletePreset={handleDeletePreset}
            midiInputs={midiInputs}
            selectedMidiInput={selectedInputId}
            onMidiInputChange={(id) => {
              setSelectedInputId(id || null);
              setMidiLearnTarget(null);
            }}
            globalSettings={globalSettings} // Pass global settings
            sessionContext={sessionContext} // Pass session context
        />

        <SettingsPanel
            isActive={activePanel === 'settings'}
            onClose={() => setActivePanel(null)}
            globalSettings={globalSettings}
            setGlobalSettings={handleGlobalSettingsChange}
        />

      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { findPlugin, INITIAL_PLUGIN_SIZES, INITIAL_PLUGIN_POSITIONS, INITIAL_PLUGIN_STATES, PluginKey, TierName } from './constants'; 
import { MixxClubLogo, HaloIcon, SaveIcon, SettingsIcon, LinkIcon, GridIcon, ResetIcon, LightbulbIcon, UploadIcon } from './components/shared/Icons';
import { HaloSchematic } from './components/HaloSchematic';
import { SessionContext, PluginPositions, PluginSize, PluginSizes, PluginPosition, SpecificPluginSettingsMap, PluginStates, MidiMappingMap, PluginComponentProps, Preset, PanelType, SidechainLink, AudioSignal, GlobalSettings } from './types'; 
import { ResizableContainer } from './components/shared/ResizableContainer';
import { motion, AnimatePresence } from 'framer-motion';
import { useMidi } from './hooks/useMidi';
import { isControlChange } from './lib/midi';
import { usePresets } from './hooks/usePresets';
import { RoutingView } from './components/RoutingView';
import { PluginBrowser } from './components/PluginBrowser';
import { SidePanel } from './components/SidePanel';
import { PrimeBrainStub } from './lib/PrimeBrainStub';
import { useSimulatedAudio } from './hooks/useSimulatedAudio';
import { SettingsPanel } from './components/SettingsPanel'; 
import { mapRange } from './lib/utils';
import { useGlobalSettings } from './hooks/useGlobalSettings';
import { AIAudioPlayer } from './components/AIAudioPlayer';
import { AmbientBackground } from './components/shared/AmbientBackground';

const App: React.FC = () => {
  const [activePlugin, setActivePlugin] = useState<PluginKey | null>(null); 
  const [view, setView] = useState<'plugin' | 'halo'>('plugin');
  const [sessionContext, setSessionContext] = useState<SessionContext>({ mood: 'Neutral' });
  const [pluginStates, setPluginStates] = useState<PluginStates>(INITIAL_PLUGIN_STATES); 
  const [pluginSizes, setPluginSizes] = useState<PluginSizes>(INITIAL_PLUGIN_SIZES);
  const [pluginPositions, setPluginPositions] = useState<PluginPositions>(INITIAL_PLUGIN_POSITIONS);
  const [activePluginZIndex, setActivePluginZIndex] = useState(10); 
  const [activePanel, setActivePanel] = useState<PanelType>(null);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isDraggingFile, setIsDraggingFile] = useState(false); // New state for file drag
  const transitionStartRef = useRef<number | null>(null);

  const { 
      audioSignal, isPlaying, loadAudio, play, pause, stopAndPlayDefault, 
      handleFileDrop, toggleMic, isMicActive 
  } = useSimulatedAudio();

  // Global Settings State using the new persistence hook
  const { globalSettings, setGlobalSettings } = useGlobalSettings();

  // Calculate dynamic transition duration based on animationIntensity
  const dynamicTransitionDuration = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 0.2);

  // MIDI State
  const { inputs: midiInputs, selectedInputId, setSelectedInputId, attachMidiListener } = useMidi();
  const [midiMappings, setMidiMappings] = useState<MidiMappingMap>({});
  const [midiLearnTarget, setMidiLearnTarget] = useState<{ pluginKey: PluginKey, paramName: string, min: number, max: number } | null>(null);

  // Preset State
  const { presets, savePreset, deletePreset } = usePresets();

  // Routing State
  const [sidechainLinks, setSidechainLinks] = useState<SidechainLink[]>([]);

  // Drag and Drop Handlers
  const handleDragOver = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingFile(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      // Only set false if leaving the window (relatedTarget is null)
      if (!e.relatedTarget) {
          setIsDraggingFile(false);
      }
  }, []);

  const handleDrop = useCallback(async (e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingFile(false);

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
          const file = e.dataTransfer.files[0];
          if (file.type.startsWith('audio/')) {
              await handleFileDrop(file);
              PrimeBrainStub.sendEvent('audio_file_dropped', { name: file.name });
          } else {
              alert("Please drop a valid audio file.");
          }
      }
  }, [handleFileDrop]);

  const handleSelectPlugin = (pluginKey: PluginKey) => {
      setIsTransitioning(true);
      transitionStartRef.current = performance.now();
      setActivePlugin(pluginKey);
      PrimeBrainStub.sendEvent('plugin_activated', { pluginKey, name: findPlugin(pluginKey).name });
  };

  const handleClosePlugin = () => {
      setIsTransitioning(true);
      transitionStartRef.current = performance.now();
      setActivePlugin(null);
  }

  // Effect to manage `isTransitioning` for a set duration after `handleSelectPlugin` or `handleClosePlugin`
  useEffect(() => {
      if (isTransitioning) {
          const timer = setTimeout(() => {
              setIsTransitioning(false);
          }, dynamicTransitionDuration * 1000 + 100); // Allow some time for the layout animation to complete
          return () => clearTimeout(timer);
      }
  }, [isTransitioning, dynamicTransitionDuration]);

  const handlePluginStateChange = useCallback(<K extends PluginKey>(
    pluginId: K, 
    newState: Partial<SpecificPluginSettingsMap[K]> | ((prevState: SpecificPluginSettingsMap[K]) => Partial<SpecificPluginSettingsMap[K]>)
  ) => {
    setPluginStates(prevStates => {
      const currentPluginState = prevStates[pluginId];
      let updatedPartialState: Partial<SpecificPluginSettingsMap[K]>;

      if (typeof newState === 'function') {
        updatedPartialState = (newState as Function)(currentPluginState);
      } else {
        updatedPartialState = newState;
      }

      return {
        ...prevStates,
        [pluginId]: {
          ...currentPluginState,
          ...updatedPartialState
        } as SpecificPluginSettingsMap[K]
      };
    });
  }, []);

  // Listen for AI commands via PrimeBrain
  useEffect(() => {
      const unsubscribe = PrimeBrainStub.subscribe('update_plugin_state', (payload: any) => {
          const { pluginId, changes } = payload;
          if (pluginId && changes) {
              handlePluginStateChange(pluginId as PluginKey, changes);
              // If we change a plugin, optionally activate it so the user sees the change
              if (activePlugin !== pluginId && payload.activate) {
                  handleSelectPlugin(pluginId as PluginKey);
              }
          }
      });
      return unsubscribe;
  }, [handlePluginStateChange, activePlugin]);

  const handleGlobalSettingsChange = useCallback((newSettings: Partial<GlobalSettings>) => {
      setGlobalSettings(newSettings); // This now uses the setter from the hook, which handles persistence
      PrimeBrainStub.sendEvent('global_settings_change', newSettings);
  }, [setGlobalSettings]);

  const handleAudioReady = useCallback(async (base64Audio: string) => {
    await loadAudio(base64Audio);
    play(); // Auto-play when ready
  }, [loadAudio, play]);


  const handleMidiMessage = useCallback((message: MIDIMessageEvent) => {
    if (!isControlChange(message) || !message.target) return;

    const [, cc, value] = message.data;
    const deviceId = (message.target as any).id;
    const mappingKey = `${deviceId}-${cc}`;

    if (midiLearnTarget) {
        const newMapping = {
            pluginKey: midiLearnTarget.pluginKey,
            paramName: midiLearnTarget.paramName,
            min: midiLearnTarget.min,
            max: midiLearnTarget.max,
        };
        setMidiMappings(prev => ({ ...prev, [mappingKey]: newMapping }));
        PrimeBrainStub.sendEvent('midi_mapped', { deviceId, cc, ...newMapping });
        setMidiLearnTarget(null);
        return;
    }

    const mapping = midiMappings[mappingKey];
    if (mapping) {
        const { pluginKey, paramName, min, max } = mapping;
        const scaledValue = min + (value / 127) * (max - min);
        handlePluginStateChange(pluginKey as PluginKey, (prevState: any) => ({
            ...prevState,
            [paramName]: scaledValue,
        }));
    }
  }, [midiLearnTarget, midiMappings, handlePluginStateChange]);

  useEffect(() => {
    const cleanup = attachMidiListener(handleMidiMessage);
    return cleanup;
  }, [attachMidiListener, handleMidiMessage]);

  const handleMidiLearnStart = useCallback((pluginKey: PluginKey, paramName: string, min: number, max: number) => {
    setMidiLearnTarget(prev => {
        if (prev && prev.pluginKey === pluginKey && prev.paramName === paramName) {
            return null;
        }
        PrimeBrainStub.sendEvent('midi_learn_started', { pluginKey, paramName });
        return { pluginKey, paramName, min, max };
    });
  }, []);

  const handleSavePreset = () => {
    const name = window.prompt("Enter a name for your preset:");
    if (name) {
      const isOverwriting = presets.some(p => p.name === name);
      if (isOverwriting) {
        if (!window.confirm(`A preset named "${name}" already exists. Overwrite it?`)) {
          return;
        }
      }
      savePreset(name, pluginStates);
      PrimeBrainStub.sendEvent('preset_saved', { name });
    }
  };

  const handleLoadPreset = (name: string) => {
    const preset = presets.find(p => p.name === name);
    if (preset) {
      setPluginStates(preset.states);
      PrimeBrainStub.sendEvent('preset_loaded', { name });
    }
  };

  const handleDeletePreset = (name: string) => {
    if (window.confirm(`Are you sure you want to delete the preset "${name}"?`)) {
      deletePreset(name);
      PrimeBrainStub.sendEvent('preset_deleted', { name });
    }
  };

  const handleAddLink = useCallback((newLink: SidechainLink) => {
    setSidechainLinks(prev => {
      if (prev.some(link => link.to === newLink.to)) return prev;
      PrimeBrainStub.sendEvent('sidechain_linked', newLink);
      return [...prev, newLink];
    });
  }, []);

  const handleRemoveLink = useCallback((linkToRemove: SidechainLink) => {
    setSidechainLinks(prev => prev.filter(link => !(link.from === linkToRemove.from && link.to === linkToRemove.to)));
    PrimeBrainStub.sendEvent('sidechain_unlinked', linkToRemove);
    const targetPluginKey = linkToRemove.to;
    const pluginInfo = findPlugin(targetPluginKey);
    if (pluginInfo.canBeSidechainTarget) {
      handlePluginStateChange(targetPluginKey, { sidechainActive: false } as any);
    }
  }, [handlePluginStateChange]);

  const handleResetSession = () => {
      if (window.confirm("Are you sure you want to reset your session? All settings will be lost.")) {
          localStorage.clear();
          PrimeBrainStub.sendEvent('session_reset', {});
          window.location.reload();
      }
  };

  const renderActivePlugin = () => {
    if (!activePlugin) return null;

    const pluginInfo = findPlugin(activePlugin);
    const ActivePluginComponent = pluginInfo.component as React.FC<PluginComponentProps<any>>;
    type CurrentPluginSettings = React.ComponentProps<typeof ActivePluginComponent>['pluginState'];

    const pluginProps = {
      name: pluginInfo.name,
      description: pluginInfo.description,
      sessionContext,
      setSessionContext: (newContext: SessionContext) => setSessionContext(newContext),
      pluginState: pluginStates[activePlugin] as CurrentPluginSettings, 
      setPluginState: (newState: Partial<CurrentPluginSettings> | ((prevState: CurrentPluginSettings) => Partial<CurrentPluginSettings>)) => handlePluginStateChange(activePlugin, newState as any),
      isLearning: (paramName: string) => midiLearnTarget?.pluginKey === activePlugin && midiLearnTarget?.paramName === paramName,
      onMidiLearn: (paramName: string, min: number, max: number) => handleMidiLearnStart(activePlugin, paramName, min, max),
      isSidechainTarget: sidechainLinks.some(link => link.to === activePlugin),
      audioSignal: audioSignal, // Pass the global audio signal here
      onClose: handleClosePlugin, // Pass the close handler to the plugin
      globalSettings: globalSettings, // Pass global settings to plugins
    };

    return (
       <ResizableContainer
        key={activePlugin}
        layoutId={activePlugin}
        initialSize={pluginSizes[activePlugin]}
        initialPosition={pluginPositions[activePlugin]}
        onResizeStop={(newSize) => setPluginSizes(prev => ({ ...prev, [activePlugin]: newSize }))}
        onDragStop={(newPosition) => setPluginPositions(prev => ({ ...prev, [activePlugin]: newPosition }))}
        onInteractionStart={() => setActivePluginZIndex(50)}
        onInteractionStop={() => setActivePluginZIndex(40)}
        zIndex={activePluginZIndex}
        onAnimationComplete={() => setIsTransitioning(false)}
        globalSettings={globalSettings} // Pass global settings
      >
        <ActivePluginComponent {...pluginProps} />
      </ResizableContainer>
    );
  };

  return (
    <div 
        className="text-white min-h-screen bg-[#0d1117] relative overflow-hidden"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
    >
      <AmbientBackground mood={sessionContext.mood} intensity={globalSettings.animationIntensity} />

      {/* File Drop Overlay */}
      <AnimatePresence>
          {isDraggingFile && (
              <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex flex-col items-center justify-center border-4 border-dashed border-cyan-500/50 pointer-events-none"
              >
                  <UploadIcon className="w-24 h-24 text-cyan-400 mb-4 animate-bounce" />
                  <h2 className="font-orbitron text-4xl font-bold text-white">DROP AUDIO TO LOAD</h2>
                  <p className="text-cyan-300 mt-2">Analyze and process your track</p>
              </motion.div>
          )}
      </AnimatePresence>

      <div className="relative flex flex-col h-screen z-10">
        <AnimatePresence>
          {activePlugin && (
            <motion.header 
              className="absolute top-0 left-0 right-0 flex items-center justify-between z-20 p-4"
              initial={{ y: -60, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: -60, opacity: 0 }}
              transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            >
                <div className="flex items-center gap-4">
                    <MixxClubLogo className="h-8 w-8" />
                    <h1 className="font-orbitron text-xl font-bold tracking-wider">MixxClub</h1>
                </div>

                <div className="flex items-center gap-2 p-2 rounded-full bg-black/30 backdrop-blur-md border border-white/20">
                    <AIAudioPlayer 
                        isPlaying={isPlaying}
                        onAudioReady={handleAudioReady}
                        onPlay={play}
                        onPause={pause}
                        onStop={stopAndPlayDefault}
                        toggleMic={toggleMic}
                        isMicActive={isMicActive}
                    />
                    <div className="w-px h-6 bg-white/20" />
                    <button onClick={handleClosePlugin} className="group p-2 text-white/60 hover:text-white transition-colors" title="Plugin Browser">
                        <GridIcon className="w-5 h-5 transition-all text-cyan-300 group-hover:drop-shadow-[0_0_3px_var(--glow-cyan)] icon-pulse-animated" />
                    </button>
                     <button onClick={() => setActivePanel('presets')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Presets">
                         <SaveIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel('settings')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Settings">
                         <SettingsIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel('routing')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Routing">
                         <LinkIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel(p => p === 'console' ? null : 'console')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="AI Console">
                         <LightbulbIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                      <button onClick={handleResetSession} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Reset Session">
                         <ResetIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button 
                        onClick={() => setView(view === 'plugin' ? 'halo' : 'plugin')}
                        className="p-2 rounded-full bg-white/10 text-cyan-300 hover:bg-cyan-400/20 hover:text-white transition-all duration-300 group hover:scale-105"
                        aria-label="Toggle Halo View"
                      >
                        <HaloIcon className="h-5 w-5 halo-icon-animated transition-all group-hover:drop-shadow-[0_0_4px_var(--glow-cyan)]" />
                     </button>
                </div>
            </motion.header>
          )}
        </AnimatePresence>

        <main className="flex-1 flex items-center justify-center transition-all duration-500">
          <AnimatePresence mode="wait">
            {view === 'halo' ? (
              <motion.div 
                key="halo" 
                initial={{opacity: 0}} 
                animate={{opacity: 1}} 
                exit={{opacity: 0}} 
                transition={{ duration: dynamicTransitionDuration, ease: 'easeInOut' }}
                className="w-full h-full"
              >
                <HaloSchematic 
                  setActivePlugin={(p: PluginKey) => { 
                    handleSelectPlugin(p); 
                    setView('plugin');
                  }} 
                  sessionContext={sessionContext}
                  pluginStates={pluginStates} 
                />
              </motion.div>
            ) : (
               activePlugin ? (
                  <div key="plugin-active" className="w-full h-full">{renderActivePlugin()}</div>
               ) : (
                  <PluginBrowser 
                    key="plugin-browser" 
                    onSelectPlugin={handleSelectPlugin} 
                    activePlugin={activePlugin}
                    isTransitioning={isTransitioning}
                    globalSettings={globalSettings} // Pass global settings
                  />
               )
            )}
          </AnimatePresence>
        </main>

        <AnimatePresence>
          {activePanel === 'routing' && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-[100]"
              transition={{ duration: dynamicTransitionDuration, ease: 'easeInOut' }}
            >
              <RoutingView 
                sidechainLinks={sidechainLinks}
                onAddLink={handleAddLink}
                onRemoveLink={handleRemoveLink}
                onClose={() => setActivePanel(null)}
              />
            </motion.div>
          )}
        </AnimatePresence>

        <SidePanel
            activePanel={activePanel}
            setActivePanel={setActivePanel}
            presets={presets}
            onSavePreset={handleSavePreset}
            onLoadPreset={handleLoadPreset}
            onDeletePreset={handleDeletePreset}
            midiInputs={midiInputs}
            selectedMidiInput={selectedInputId}
            onMidiInputChange={(id) => {
              setSelectedInputId(id || null);
              setMidiLearnTarget(null);
            }}
            globalSettings={globalSettings} // Pass global settings
            sessionContext={sessionContext} // Pass session context
        />

        <SettingsPanel
            isActive={activePanel === 'settings'}
            onClose={() => setActivePanel(null)}
            globalSettings={globalSettings}
            setGlobalSettings={handleGlobalSettingsChange}
        />

      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { SessionContext } from '../../types';
import { PrimeBrainStub } from '../../lib/PrimeBrainStub';
import { PLUGIN_TIERS, PluginKey } from '../../constants';

const PrimeBotAvatar: React.FC<{hue: number, isThinking?: boolean}> = ({ hue, isThinking }) => (
    <div className="relative w-8 h-8 flex-shrink-0">
        <div className={`absolute inset-0 rounded-full transition-all duration-300 ${isThinking ? 'animate-spin' : ''}`} style={{
            backgroundColor: `hsl(${hue}, 80%, 30%)`,
            boxShadow: `0 0 10px hsl(${hue}, 80%, 50%)`,
            animation: isThinking ? 'spin 1s linear infinite' : 'pulse-meter 4s infinite ease-in-out',
            borderTop: isThinking ? '2px solid white' : 'none'
        }}/>
        <div className="absolute inset-2 rounded-full bg-black/50"/>
    </div>
);

interface PrimeBotConsoleViewProps {
  sessionContext: SessionContext;
}

// Helper to get all available plugins and params for context
const getSystemContext = () => {
    const plugins = [];
    for (const tier of Object.values(PLUGIN_TIERS)) {
        for (const [key, p] of Object.entries(tier)) {
            plugins.push(`${p.name} (ID: ${key}): [${p.parameters.join(', ')}] - ${p.description}`);
        }
    }
    return `You are PrimeBot 4.0, an AI audio engineer. You control a suite of plugins. 
Available Plugins:
${plugins.join('\n')}

When asked to change sound, use the 'adjust_plugin_parameter' tool. 
Be concise and futuristic in your responses.`;
};

// Define the Tool
const adjustPluginTool: FunctionDeclaration = {
    name: 'adjust_plugin_parameter',
    description: 'Adjusts a specific parameter of a plugin.',
    parameters: {
        type: Type.OBJECT,
        properties: {
            pluginId: { type: Type.STRING, description: 'The exact ID of the plugin (e.g., "mixx-verb", "mixx-tune").' },
            parameter: { type: Type.STRING, description: 'The parameter name (e.g., "size", "mix", "drive").' },
            value: { type: Type.NUMBER, description: 'The new value for the parameter (usually 0-100).' },
            activate: { type: Type.BOOLEAN, description: 'Whether to switch the view to this plugin (default true).' }
        },
        required: ['pluginId', 'parameter', 'value']
    }
};

const PrimeBotConsole: React.FC<PrimeBotConsoleViewProps> = ({ sessionContext }) => {
    const [messages, setMessages] = useState<{sender: 'bot'|'user', text: string}[]>([
        {sender: 'bot', text: "[PrimeBot 4.0] Neural Link Active. Awaiting command."}
    ]);
    const [input, setInput] = useState('');
    const [isThinking, setIsThinking] = useState(false);
    const consoleEndRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    // Auto-scroll
    useEffect(() => {
        consoleEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    // Focus input on mount
    useEffect(() => {
        inputRef.current?.focus();
    }, []);

    // Handle incoming system events
    useEffect(() => {
        const handleEvent = (eventName: string) => (payload: any) => {
            let newMessage = '';
            switch (eventName) {
                case 'plugin_activated':
                    newMessage = `[INFO] ${payload.name} engaged.`;
                    break;
                case 'preset_loaded':
                    newMessage = `[LOAD] Preset '${payload.name}' restored.`;
                    break;
                case 'session_reset':
                    newMessage = `[WARN] Session reset.`;
                    break;
                default:
                    return;
            }
            setMessages(prev => [...prev.slice(-40), {sender: 'bot', text: newMessage}]);
        };

        const eventNames = ['plugin_activated', 'preset_loaded', 'session_reset'];
        const unsubscribers = eventNames.map(eventName => PrimeBrainStub.subscribe(eventName, handleEvent(eventName)));

        return () => unsubscribers.forEach(unsub => unsub());
    }, []);

    const handleSend = async () => {
        if (!input.trim() || isThinking) return;

        const userMsg = input;
        setInput('');
        setMessages(prev => [...prev, {sender: 'user', text: userMsg}]);
        setIsThinking(true);

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash-preview-09-2025', // Using specific preview model as per guidelines
                contents: [
                    { role: 'user', parts: [{ text: getSystemContext() + `\n\nUser Command: ${userMsg}` }] }
                ],
                config: {
                    tools: [{ functionDeclarations: [adjustPluginTool] }],
                }
            });

            // Handle Tool Calls
            const functionCalls = response.candidates?.[0]?.content?.parts?.[0]?.functionCall 
                ? [response.candidates[0].content.parts[0].functionCall] 
                : (response.functionCalls || []);

            if (functionCalls.length > 0) {
                const fc = functionCalls[0]; // Handle first call for now
                if (fc.name === 'adjust_plugin_parameter') {
                    const { pluginId, parameter, value, activate } = fc.args as any;

                    // Dispatch event to App
                    PrimeBrainStub.sendEvent('update_plugin_state', {
                        pluginId, 
                        changes: { [parameter]: value },
                        activate: activate !== false 
                    });

                    setMessages(prev => [...prev, {sender: 'bot', text: `[EXEC] Adjusting ${pluginId}.${parameter} to ${value}.`}]);
                }
            } else {
                // If no tool call, just show text response
                const text = response.text || "[ERR] Could not parse command.";
                setMessages(prev => [...prev, {sender: 'bot', text: text}]);
            }

        } catch (e) {
            console.error(e);
            setMessages(prev => [...prev, {sender: 'bot', text: `[ERR] Neural Link Failure: ${e instanceof Error ? e.message : 'Unknown error'}`}]);
        } finally {
            setIsThinking(false);
            // Re-focus input
            setTimeout(() => inputRef.current?.focus(), 100);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') handleSend();
    };

    const hueMap: Record<string, number> = {
        Neutral: 220, Warm: 40, Bright: 190, Dark: 260, Energetic: 330
    };
    const hue = hueMap[sessionContext.mood] || 220;
    const accentColor = `hsl(${hue}, 80%, 75%)`;

    return (
        <div className="w-full h-full flex flex-col p-4 font-mono text-sm">
             <div className="flex-shrink-0 flex items-center gap-2 mb-2 pb-2 border-b border-white/10">
                <PrimeBotAvatar hue={hue} isThinking={isThinking} />
                <h4 className="font-bold tracking-wider" style={{color: accentColor}}>PRIMEBOT CONSOLE</h4>
             </div>

            <div className="relative flex-1 overflow-y-auto custom-scrollbar pr-2 mb-2 bg-black/20 rounded-lg p-2 scanline-bg flex flex-col gap-1">
                {messages.map((msg, i) => (
                    <div key={i} className={`break-words ${msg.sender === 'user' ? 'text-right opacity-70 italic' : ''}`}>
                        <span style={{ 
                            color: msg.sender === 'bot' ? accentColor : 'white', 
                            textShadow: msg.sender === 'bot' ? `0 0 5px hsl(${hue}, 80%, 50%)` : 'none'
                        }}>
                            {msg.sender === 'bot' && <span className="mr-2 opacity-50">{'>'}</span>}
                            {msg.text}
                        </span>
                    </div>
                ))}
                {isThinking && <div className="text-xs animate-pulse opacity-50" style={{color: accentColor}}>PROCESSING...</div>}
                <div ref={consoleEndRef} />
            </div>

            <div className="flex-shrink-0 flex items-center gap-2 bg-black/40 border border-white/20 rounded px-2 py-1 focus-within:border-cyan-400 focus-within:shadow-[0_0_10px_rgba(34,211,238,0.2)] transition-all">
                <span className="text-cyan-500 font-bold">{'>'}</span>
                <input 
                    ref={inputRef}
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={handleKeyDown}
                    className="flex-1 bg-transparent border-none outline-none text-white placeholder-white/20"
                    placeholder="Enter command..."
                    disabled={isThinking}
                />
            </div>
        </div>
    );
};

export { PrimeBotConsole };

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { findPlugin, INITIAL_PLUGIN_SIZES, INITIAL_PLUGIN_POSITIONS, INITIAL_PLUGIN_STATES, PluginKey, TierName } from './constants'; 
import { MixxClubLogo, HaloIcon, SaveIcon, SettingsIcon, LinkIcon, GridIcon, ResetIcon, LightbulbIcon, UploadIcon } from './components/shared/Icons';
import { HaloSchematic } from './components/HaloSchematic';
import { SessionContext, PluginPositions, PluginSize, PluginSizes, PluginPosition, SpecificPluginSettingsMap, PluginStates, MidiMappingMap, PluginComponentProps, Preset, PanelType, SidechainLink, AudioSignal, GlobalSettings } from './types'; 
import { ResizableContainer } from './components/shared/ResizableContainer';
import { motion, AnimatePresence } from 'framer-motion';
import { useMidi } from './hooks/useMidi';
import { isControlChange } from './lib/midi';
import { usePresets } from './hooks/usePresets';
import { RoutingView } from './components/RoutingView';
import { PluginBrowser } from './components/PluginBrowser';
import { SidePanel } from './components/SidePanel';
import { PrimeBrainStub } from './lib/PrimeBrainStub';
import { useSimulatedAudio } from './hooks/useSimulatedAudio';
import { SettingsPanel } from './components/SettingsPanel'; 
import { mapRange } from './lib/utils';
import { useGlobalSettings } from './hooks/useGlobalSettings';
import { AIAudioPlayer } from './components/AIAudioPlayer';
import { AmbientBackground } from './components/shared/AmbientBackground';

const App: React.FC = () => {
  const [activePlugin, setActivePlugin] = useState<PluginKey | null>(null); 
  const [view, setView] = useState<'plugin' | 'halo'>('plugin');
  const [sessionContext, setSessionContext] = useState<SessionContext>({ mood: 'Neutral' });
  const [pluginStates, setPluginStates] = useState<PluginStates>(INITIAL_PLUGIN_STATES); 
  const [pluginSizes, setPluginSizes] = useState<PluginSizes>(INITIAL_PLUGIN_SIZES);
  const [pluginPositions, setPluginPositions] = useState<PluginPositions>(INITIAL_PLUGIN_POSITIONS);
  const [activePluginZIndex, setActivePluginZIndex] = useState(10); 
  const [activePanel, setActivePanel] = useState<PanelType>(null);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isDraggingFile, setIsDraggingFile] = useState(false); // New state for file drag
  const transitionStartRef = useRef<number | null>(null);

  const { 
      audioSignal, isPlaying, loadAudio, play, pause, stopAndPlayDefault, 
      handleFileDrop, toggleMic, isMicActive 
  } = useSimulatedAudio();

  // Global Settings State using the new persistence hook
  const { globalSettings, setGlobalSettings } = useGlobalSettings();

  // Calculate dynamic transition duration based on animationIntensity
  const dynamicTransition duration = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 0.2);

  // MIDI State
  const { inputs: midiInputs, selectedInputId, setSelectedInputId, attachMidiListener } = useMidi();
  const [midiMappings, setMidiMappings] = useState<MidiMappingMap>({});
  const [midiLearnTarget, setMidiLearnTarget] = useState<{ pluginKey: PluginKey, paramName: string, min: number, max: number } | null>(null);

  // Preset State
  const { presets, savePreset, deletePreset } = usePresets();

  // Routing State
  const [sidechainLinks, setSidechainLinks] = useState<SidechainLink[]>([]);

  // Drag and Drop Handlers
  const handleDragOver = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingFile(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
      e.preventDefault();
      // Only set false if leaving the window (relatedTarget is null)
      if (!e.relatedTarget) {
          setIsDraggingFile(false);
      }
  }, []);

  const handleDrop = useCallback(async (e: React.DragEvent) => {
      e.preventDefault();
      setIsDraggingFile(false);

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
          const file = e.dataTransfer.files[0];
          if (file.type.startsWith('audio/')) {
              await handleFileDrop(file);
              PrimeBrainStub.sendEvent('audio_file_dropped', { name: file.name });
          } else {
              alert("Please drop a valid audio file.");
          }
      }
  }, [handleFileDrop]);

  const handleSelectPlugin = (pluginKey: PluginKey) => {
      setIsTransitioning(true);
      transitionStartRef.current = performance.now();
      setActivePlugin(pluginKey);
      PrimeBrainStub.sendEvent('plugin_activated', { pluginKey, name: findPlugin(pluginKey).name });
  };

  const handleClosePlugin = () => {
      setIsTransitioning(true);
      transitionStartRef.current = performance.now();
      setActivePlugin(null);
  }

  // Effect to manage `isTransitioning` for a set duration after `handleSelectPlugin` or `handleClosePlugin`
  useEffect(() => {
      if (isTransitioning) {
          const timer = setTimeout(() => {
              setIsTransitioning(false);
          }, dynamicTransitionDuration * 1000 + 100); // Allow some time for the layout animation to complete
          return () => clearTimeout(timer);
      }
  }, [isTransitioning, dynamicTransitionDuration]);

  const handlePluginStateChange = useCallback(<K extends PluginKey>(
    pluginId: K, 
    newState: Partial<SpecificPluginSettingsMap[K]> | ((prevState: SpecificPluginSettingsMap[K]) => Partial<SpecificPluginSettingsMap[K]>)
  ) => {
    setPluginStates(prevStates => {
      const currentPluginState = prevStates[pluginId];
      let updatedPartialState: Partial<SpecificPluginSettingsMap[K]>;

      if (typeof newState === 'function') {
        updatedPartialState = (newState as Function)(currentPluginState);
      } else {
        updatedPartialState = newState;
      }

      return {
        ...prevStates,
        [pluginId]: {
          ...currentPluginState,
          ...updatedPartialState
        } as SpecificPluginSettingsMap[K]
      };
    });
  }, []);

  // Listen for AI commands via PrimeBrain
  useEffect(() => {
      const unsubscribe = PrimeBrainStub.subscribe('update_plugin_state', (payload: any) => {
          const { pluginId, changes } = payload;
          if (pluginId && changes) {
              handlePluginStateChange(pluginId as PluginKey, changes);
              // If we change a plugin, optionally activate it so the user sees the change
              if (activePlugin !== pluginId && payload.activate) {
                  handleSelectPlugin(pluginId as PluginKey);
              }
          }
      });
      return unsubscribe;
  }, [handlePluginStateChange, activePlugin]);

  const handleGlobalSettingsChange = useCallback((newSettings: Partial<GlobalSettings>) => {
      setGlobalSettings(newSettings); // This now uses the setter from the hook, which handles persistence
      PrimeBrainStub.sendEvent('global_settings_change', newSettings);
  }, [setGlobalSettings]);

  const handleAudioReady = useCallback(async (base64Audio: string) => {
    await loadAudio(base64Audio);
    play(); // Auto-play when ready
  }, [loadAudio, play]);


  const handleMidiMessage = useCallback((message: MIDIMessageEvent) => {
    if (!isControlChange(message) || !message.target) return;

    const [, cc, value] = message.data;
    const deviceId = (message.target as any).id;
    const mappingKey = `${deviceId}-${cc}`;

    if (midiLearnTarget) {
        const newMapping = {
            pluginKey: midiLearnTarget.pluginKey,
            paramName: midiLearnTarget.paramName,
            min: midiLearnTarget.min,
            max: midiLearnTarget.max,
        };
        setMidiMappings(prev => ({ ...prev, [mappingKey]: newMapping }));
        PrimeBrainStub.sendEvent('midi_mapped', { deviceId, cc, ...newMapping });
        setMidiLearnTarget(null);
        return;
    }

    const mapping = midiMappings[mappingKey];
    if (mapping) {
        const { pluginKey, paramName, min, max } = mapping;
        const scaledValue = min + (value / 127) * (max - min);
        handlePluginStateChange(pluginKey as PluginKey, (prevState: any) => ({
            ...prevState,
            [paramName]: scaledValue,
        }));
    }
  }, [midiLearnTarget, midiMappings, handlePluginStateChange]);

  useEffect(() => {
    const cleanup = attachMidiListener(handleMidiMessage);
    return cleanup;
  }, [attachMidiListener, handleMidiMessage]);

  const handleMidiLearnStart = useCallback((pluginKey: PluginKey, paramName: string, min: number, max: number) => {
    setMidiLearnTarget(prev => {
        if (prev && prev.pluginKey === pluginKey && prev.paramName === paramName) {
            return null;
        }
        PrimeBrainStub.sendEvent('midi_learn_started', { pluginKey, paramName });
        return { pluginKey, paramName, min, max };
    });
  }, []);

  const handleSavePreset = () => {
    const name = window.prompt("Enter a name for your preset:");
    if (name) {
      const isOverwriting = presets.some(p => p.name === name);
      if (isOverwriting) {
        if (!window.confirm(`A preset named "${name}" already exists. Overwrite it?`)) {
          return;
        }
      }
      savePreset(name, pluginStates);
      PrimeBrainStub.sendEvent('preset_saved', { name });
    }
  };

  const handleLoadPreset = (name: string) => {
    const preset = presets.find(p => p.name === name);
    if (preset) {
      setPluginStates(preset.states);
      PrimeBrainStub.sendEvent('preset_loaded', { name });
    }
  };

  const handleDeletePreset = (name: string) => {
    if (window.confirm(`Are you sure you want to delete the preset "${name}"?`)) {
      deletePreset(name);
      PrimeBrainStub.sendEvent('preset_deleted', { name });
    }
  };

  const handleAddLink = useCallback((newLink: SidechainLink) => {
    setSidechainLinks(prev => {
      if (prev.some(link => link.to === newLink.to)) return prev;
      PrimeBrainStub.sendEvent('sidechain_linked', newLink);
      return [...prev, newLink];
    });
  }, []);

  const handleRemoveLink = useCallback((linkToRemove: SidechainLink) => {
    setSidechainLinks(prev => prev.filter(link => !(link.from === linkToRemove.from && link.to === linkToRemove.to)));
    PrimeBrainStub.sendEvent('sidechain_unlinked', linkToRemove);
    const targetPluginKey = linkToRemove.to;
    const pluginInfo = findPlugin(targetPluginKey);
    if (pluginInfo.canBeSidechainTarget) {
      handlePluginStateChange(targetPluginKey, { sidechainActive: false } as any);
    }
  }, [handlePluginStateChange]);

  const handleResetSession = () => {
      if (window.confirm("Are you sure you want to reset your session? All settings will be lost.")) {
          localStorage.clear();
          PrimeBrainStub.sendEvent('session_reset', {});
          window.location.reload();
      }
  };

  const renderActivePlugin = () => {
    if (!activePlugin) return null;

    const pluginInfo = findPlugin(activePlugin);
    const ActivePluginComponent = pluginInfo.component as React.FC<PluginComponentProps<any>>;
    type CurrentPluginSettings = React.ComponentProps<typeof ActivePluginComponent>['pluginState'];

    const pluginProps = {
      name: pluginInfo.name,
      description: pluginInfo.description,
      sessionContext,
      setSessionContext: (newContext: SessionContext) => setSessionContext(newContext),
      pluginState: pluginStates[activePlugin] as CurrentPluginSettings, 
      setPluginState: (newState: Partial<CurrentPluginSettings> | ((prevState: CurrentPluginSettings) => Partial<CurrentPluginSettings>)) => handlePluginStateChange(activePlugin, newState as any),
      isLearning: (paramName: string) => midiLearnTarget?.pluginKey === activePlugin && midiLearnTarget?.paramName === paramName,
      onMidiLearn: (paramName: string, min: number, max: number) => handleMidiLearnStart(activePlugin, paramName, min, max),
      isSidechainTarget: sidechainLinks.some(link => link.to === activePlugin),
      audioSignal: audioSignal, // Pass the global audio signal here
      onClose: handleClosePlugin, // Pass the close handler to the plugin
      globalSettings: globalSettings, // Pass global settings to plugins
    };

    return (
       <ResizableContainer
        key={activePlugin}
        layoutId={activePlugin}
        initialSize={pluginSizes[activePlugin]}
        initialPosition={pluginPositions[activePlugin]}
        onResizeStop={(newSize) => setPluginSizes(prev => ({ ...prev, [activePlugin]: newSize }))}
        onDragStop={(newPosition) => setPluginPositions(prev => ({ ...prev, [activePlugin]: newPosition }))}
        onInteractionStart={() => setActivePluginZIndex(50)}
        onInteractionStop={() => setActivePluginZIndex(40)}
        zIndex={activePluginZIndex}
        onAnimationComplete={() => setIsTransitioning(false)}
        globalSettings={globalSettings} // Pass global settings
      >
        <ActivePluginComponent {...pluginProps} />
      </ResizableContainer>
    );
  };

  return (
    <div 
        className="text-white min-h-screen bg-[#0d1117] relative overflow-hidden"
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
    >
      <AmbientBackground mood={sessionContext.mood} intensity={globalSettings.animationIntensity} />

      {/* File Drop Overlay */}
      <AnimatePresence>
          {isDraggingFile && (
              <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex flex-col items-center justify-center border-4 border-dashed border-cyan-500/50 pointer-events-none"
              >
                  <UploadIcon className="w-24 h-24 text-cyan-400 mb-4 animate-bounce" />
                  <h2 className="font-orbitron text-4xl font-bold text-white">DROP AUDIO TO LOAD</h2>
                  <p className="text-cyan-300 mt-2">Analyze and process your track</p>
              </motion.div>
          )}
      </AnimatePresence>

      <div className="relative flex flex-col h-screen z-10">
        <AnimatePresence>
          {activePlugin && (
            <motion.header 
              className="absolute top-0 left-0 right-0 flex items-center justify-between z-20 p-4"
              initial={{ y: -60, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: -60, opacity: 0 }}
              transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            >
                <div className="flex items-center gap-4">
                    <MixxClubLogo className="h-8 w-8" />
                    <h1 className="font-orbitron text-xl font-bold tracking-wider">MixxClub</h1>
                </div>

                <div className="flex items-center gap-2 p-2 rounded-full bg-black/30 backdrop-blur-md border border-white/20">
                    <AIAudioPlayer 
                        isPlaying={isPlaying}
                        onAudioReady={handleAudioReady}
                        onPlay={play}
                        onPause={pause}
                        onStop={stopAndPlayDefault}
                        toggleMic={toggleMic}
                        isMicActive={isMicActive}
                    />
                    <div className="w-px h-6 bg-white/20" />
                    <button onClick={handleClosePlugin} className="group p-2 text-white/60 hover:text-white transition-colors" title="Plugin Browser">
                        <GridIcon className="w-5 h-5 transition-all text-cyan-300 group-hover:drop-shadow-[0_0_3px_var(--glow-cyan)] icon-pulse-animated" />
                    </button>
                     <button onClick={() => setActivePanel('presets')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Presets">
                         <SaveIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel('settings')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Settings">
                         <SettingsIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel('routing')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Routing">
                         <LinkIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button onClick={() => setActivePanel(p => p === 'console' ? null : 'console')} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="AI Console">
                         <LightbulbIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                      <button onClick={handleResetSession} className="group p-2 text-white/60 hover:text-white transition-all duration-300 hover:scale-105" title="Reset Session">
                         <ResetIcon className="w-5 h-5 transition-all group-hover:drop-shadow-[0_0_4px_white]" />
                     </button>
                     <button 
                        onClick={() => setView(view === 'plugin' ? 'halo' : 'plugin')}
                        className="p-2 rounded-full bg-white/10 text-cyan-300 hover:bg-cyan-400/20 hover:text-white transition-all duration-300 group hover:scale-105"
                        aria-label="Toggle Halo View"
                      >
                        <HaloIcon className="h-5 w-5 halo-icon-animated transition-all group-hover:drop-shadow-[0_0_4px_var(--glow-cyan)]" />
                     </button>
                </div>
            </motion.header>
          )}
        </AnimatePresence>

        <main className="flex-1 flex items-center justify-center transition-all duration-500">
          <AnimatePresence mode="wait">
            {view === 'halo' ? (
              <motion.div 
                key="halo" 
                initial={{opacity: 0}} 
                animate={{opacity: 1}} 
                exit={{opacity: 0}} 
                transition={{ duration: dynamicTransitionDuration, ease: 'easeInOut' }}
                className="w-full h-full"
              >
                <HaloSchematic 
                  setActivePlugin={(p: PluginKey) => { 
                    handleSelectPlugin(p); 
                    setView('plugin');
                  }} 
                  sessionContext={sessionContext}
                  pluginStates={pluginStates} 
                />
              </motion.div>
            ) : (
               activePlugin ? (
                  <div key="plugin-active" className="w-full h-full">{renderActivePlugin()}</div>
               ) : (
                  <PluginBrowser 
                    key="plugin-browser" 
                    onSelectPlugin={handleSelectPlugin} 
                    activePlugin={activePlugin}
                    isTransitioning={isTransitioning}
                    globalSettings={globalSettings} // Pass global settings
                  />
               )
            )}
          </AnimatePresence>
        </main>

        <AnimatePresence>
          {activePanel === 'routing' && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-[100]"
              transition={{ duration: dynamicTransitionDuration, ease: 'easeInOut' }}
            >
              <RoutingView 
                sidechainLinks={sidechainLinks}
                onAddLink={handleAddLink}
                onRemoveLink={handleRemoveLink}
                onClose={() => setActivePanel(null)}
              />
            </motion.div>
          )}
        </AnimatePresence>

        <SidePanel
            activePanel={activePanel}
            setActivePanel={setActivePanel}
            presets={presets}
            onSavePreset={handleSavePreset}
            onLoadPreset={handleLoadPreset}
            onDeletePreset={handleDeletePreset}
            midiInputs={midiInputs}
            selectedMidiInput={selectedInputId}
            onMidiInputChange={(id) => {
              setSelectedInputId(id || null);
              setMidiLearnTarget(null);
            }}
            globalSettings={globalSettings} // Pass global settings
            sessionContext={sessionContext} // Pass session context
        />

        <SettingsPanel
            isActive={activePanel === 'settings'}
            onClose={() => setActivePanel(null)}
            globalSettings={globalSettings}
            setGlobalSettings={handleGlobalSettingsChange}
        />

      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { SessionContext } from '../../types';
