import React, { useMemo } from 'react';
import { PluginContainer } from '../shared/PluginContainer';
import { Knob } from '../shared/Knob';
import { MixxTunnelSettings, PluginComponentProps, AudioSignal, GlobalSettings } from '../../types';
import { PrimeBrainStub } from '../../lib/PrimeBrainStub';
import { VstBridge, VisualizerData } from '../../vst/VstBridge';
import { useVstBridge } from '../../vst/useVstBridge';
import { mapRange } from '../../lib/utils';

interface TunnelRing {
    id: number;
    z: number; // Depth position: 0 (near) to 1 (far/horizon)
    rotation: number;
    segments: number;
}

interface TunnelVisualizerData extends VisualizerData {
    rings: TunnelRing[];
    horizonRadiusPercent: number;
    coreColor: string;
    gridColor: string;
    audioImpact: number;
}

class MixxTunnelVstBridge extends VstBridge<MixxTunnelSettings> {
    private rings: TunnelRing[] = [];
    private ringIdCounter = 0;

    constructor(initialSettings: MixxTunnelSettings) {
        super(initialSettings);
        // Initialize pool
        for(let i=0; i<15; i++) {
            this.spawnRing(i/15);
        }
    }

    private spawnRing(startZ: number = 0) {
        this.rings.push({
            id: this.ringIdCounter++,
            z: startZ,
            rotation: Math.random() * 360,
            segments: Math.floor(Math.random() * 3) + 3 // 3 to 5 segments per ring for variety
        });
    }

    public dspProcess(
        audioSignal: AudioSignal,
        width: number,
        height: number,
        globalSettings: GlobalSettings
    ): TunnelVisualizerData {
        const { length, gravity, horizon, mix } = this.settings;

        // Simulation constants
        const animationSpeedMultiplier = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 2.0);
        // Length parameter inversely controls speed (longer tunnel = things take longer to traverse)
        const speedBase = 0.005 + (100 - length) / 100 * 0.015;
        const speed = speedBase * animationSpeedMultiplier;

        // Gravity controls the acceleration curve. Higher gravity = faster pull towards horizon (z=1)
        const gravityFactor = 1 + (gravity / 100) * 2; 

        // Horizon controls the visual size of the center
        const horizonRadiusPercent = 5 + (horizon / 100) * 20;

        // Audio reactivity
        const audioImpact = (audioSignal.level / 100) * (mix / 100);

        // Update rings
        this.rings.forEach(ring => {
            // Move z from 0 to 1
            // Apply non-linear movement based on current Z and gravity
            // As Z gets closer to 1, it might speed up or slow down depending on visual preference.
            // Here, let's make them accelerate into the hole.
            const zStep = speed * Math.pow(1 + ring.z, gravityFactor); 
            ring.z += zStep;

            // Rotate rings
            ring.rotation += 0.2 + audioImpact * 2;
        });

        // Remove rings that hit the horizon (z >= 1)
        this.rings = this.rings.filter(r => r.z < 1);

        // Spawn new rings at z=0 if we have gaps
        // We want a constant stream.
        const density = 20 + (length / 100) * 20; 
        if (this.rings.length < density) {
            // Only spawn if the most recent ring has moved far enough in
            const minZ = Math.min(...this.rings.map(r => r.z));
            if (minZ > (1 / density)) {
                this.spawnRing(0);
            }
        }

        // Sort painter's algo: Farthest (z=1) first? No, for tunnel looking IN, farthest is "behind" usually, 
        // but since we are drawing borders, drawing back-to-front (high Z to low Z) ensures overlap occlusion if filled.
        // We are drawing strokes mostly, but sorting by depth helps visual logic.
        // Z=1 is deep in screen. Z=0 is face. Draw Z=1 first.
        this.rings.sort((a, b) => b.z - a.z);

        const hue = 260; // Deep Indigo/Purple
        const coreColor = `hsl(${hue}, 80%, ${5 + audioImpact * 40}%)`;
        const gridColor = `hsl(${hue - 40}, 90%, ${60 + audioImpact * 20}%)`;

        return {
            rings: this.rings,
            horizonRadiusPercent,
            coreColor,
            gridColor,
            audioImpact
        };
    }
}

const TunnelVisualizer: React.FC<{ data: TunnelVisualizerData | null }> = ({ data }) => {
    if (!data) return <div className="w-full h-full bg-black/20" />;
    const { rings, horizonRadiusPercent, coreColor, gridColor, audioImpact } = data;

