                        <feGaussianBlur stdDeviation="1" result="coloredBlur"/>
                        <feMerge>
                            <feMergeNode in="coloredBlur"/>
                            <feMergeNode in="SourceGraphic"/>
                        </feMerge>
                    </filter>
                </defs>
                {rings.map(ring => {
                    // Perspective projection
                    // Z goes 0 -> 1 (Face -> Horizon)
                    // Radius needs to go Max -> HorizonRadius
                    // Let's map Z linearly for simple perspective first, then apply curvature if needed.

                    const maxRadius = 140; 
                    const minRadius = horizonRadiusPercent; // in SVG units roughly if viewBox is 200x200, % ~ units * 2

                    // Map Z [0,1] to Radius [140, minRadius]
                    // Non-linear mapping for "deep" feel: 1 / (z + c)

                    // Simple linear interpolation between Outer Screen and Horizon
                    const currentRadius = maxRadius - (maxRadius - minRadius) * ring.z;

                    const opacity = Math.pow(ring.z, 2); // Fade in as they go deep? Or fade out?
                    // Typically tunnels are dark at end, bright near you? Or "light at end of tunnel"?
                    // Let's make rings brighter as they approach horizon to simulate energy density.
                    const strokeOpacity = 0.1 + ring.z * 0.9;
                    const strokeWidth = 0.5 + (1 - ring.z) * 1.5;

                    return (
                        <g key={ring.id} transform={`rotate(${ring.rotation} 100 100)`}>
                            <circle 
                                cx="100" cy="100" r={Math.max(0, currentRadius)}
                                fill="none"
                                stroke={gridColor}
                                strokeWidth={strokeWidth}
                                strokeOpacity={strokeOpacity}
                                strokeDasharray={`${10 + audioImpact * 20} ${10}`}
                                style={{ filter: 'url(#tunnel-glow)' }}
                            />
                            {/* Optional connection lines to center could be added here for 'wireframe' look */}
                        </g>
                    );
                })}
            </svg>
        </div>
    );
};

