interface TunnelRing {
    id: number;
    z: number; // Depth position: 0 (near/face) to 1 (far/horizon)
    rotation: number;
    segments: number;
    speedOffset: number;
}

interface TunnelVisualizerData extends VisualizerData {
    rings: TunnelRing[];
    horizonRadiusPercent: number;
    coreColor: string;
    gridColor: string;
    audioImpact: number;
}

class MixxTunnelVstBridge extends VstBridge<MixxTunnelSettings> {
    private rings: TunnelRing[] = [];
    private ringIdCounter = 0;

    constructor(initialSettings: MixxTunnelSettings) {
        super(initialSettings);
        // Initialize pool
        for(let i=0; i<20; i++) {
            this.spawnRing(Math.random());
        }
        // Sort initial to ensure correct z-order
        this.rings.sort((a, b) => b.z - a.z);
    }

    private spawnRing(startZ: number = 0) {
        this.rings.push({
            id: this.ringIdCounter++,
            z: startZ,
            rotation: Math.random() * 360,
            segments: Math.floor(Math.random() * 4) + 2, // 2 to 5 segments
            speedOffset: 0.9 + Math.random() * 0.2 // Slight speed variation
        });
    }

    public dspProcess = (
        audioSignal: AudioSignal,
        width: number,
        height: number,
        globalSettings: GlobalSettings
    ): TunnelVisualizerData => {
        const { length, gravity, horizon, mix } = this.settings;

        // Simulation constants
        const animationSpeedMultiplier = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 2.0);

        // Length parameter inversely controls speed (longer tunnel = slower speed)
        // Range: 0 (Fast) to 100 (Slow)
        const baseSpeed = (0.015 - (length / 100) * 0.012) * animationSpeedMultiplier;

        // Gravity controls acceleration curve. 
        // 0 = Linear movement, 100 = High acceleration near center
        const gravityExp = 1 + (gravity / 100) * 3; 

        // Horizon controls the visual size of the center void
        const horizonRadiusPercent = 5 + (horizon / 100) * 25;

        // Audio reactivity
        const audioImpact = (audioSignal.level / 100) * (mix / 100);
        const transientBoost = audioSignal.transients ? 0.02 : 0;

        // Update rings
        const activeRings: TunnelRing[] = [];

        this.rings.forEach(ring => {
            // Move z from 0 (screen) to 1 (horizon)
            // We apply the speed to the raw linear progress, but render based on gravity
            // Actually, simply advancing Z linearly and mapping it exponentially for rendering is easier,
            // BUT "Gravity" implies acceleration. So let's accelerate Z.

            const currentSpeed = baseSpeed * Math.pow(1 + ring.z, gravityExp - 1) + transientBoost;
            ring.z += currentSpeed * ring.speedOffset;

            // Rotate rings based on audio
            ring.rotation += (0.2 + audioImpact * 2) * (1 + ring.z); // Faster rotation deeper in tunnel

            if (ring.z < 1) {
                activeRings.push(ring);
            }
        });

        this.rings = activeRings;

        // Spawn new rings to maintain density
        // Higher density for "Longer" tunnels to look populated
        const desiredCount = 15 + (length / 100) * 15; 
        if (this.rings.length < desiredCount) {
            // Only spawn if the most recent ring (lowest z) has moved far enough in
            // or if we are just starting up
            const minZ = this.rings.length > 0 ? Math.min(...this.rings.map(r => r.z)) : 1;
            if (minZ > (1 / desiredCount) * 0.5) {
                this.spawnRing(0);
            }
        }

        // Sort for painter's algorithm: Draw deepest (Z near 1) first?
        // Actually for a tunnel, we want to draw the FARTHEST things first so near things occlude them.
        // Z=1 is farthest (Horizon). Z=0 is nearest (Screen).
        // So sort descending Z.
        this.rings.sort((a, b) => b.z - a.z);

        const hue = 260; // Deep Indigo/Purple (Quantum Tier)
        const coreColor = `hsl(${hue}, 80%, ${5 + audioImpact * 30}%)`;
        const gridColor = `hsl(${hue - 40}, 90%, ${60 + audioImpact * 20}%)`;

        return {
            rings: this.rings,
            horizonRadiusPercent,
            coreColor,
            gridColor,
            audioImpact
        };
    }
}

const TunnelVisualizer: React.FC<{ data: TunnelVisualizerData | null }> = ({ data }) => {
    if (!data) return <div className="w-full h-full bg-black/20" />;
    const { rings, horizonRadiusPercent, coreColor, gridColor, audioImpact } = data;

    return (
        <div className="relative w-full h-full flex items-center justify-center bg-black/40 rounded-lg overflow-hidden border border-indigo-500/20 shadow-[inset_0_0_50px_rgba(0,0,0,0.8)]">

