            <div className="absolute rounded-full blur-xl" 
                style={{
                    width: `${horizonRadiusPercent * 2}%`,
                    height: `${horizonRadiusPercent * 2}%`,
                    background: coreColor,
                    opacity: 0.6,
                    transition: 'all 0.1s ease-out'
                }} 
            />
            {/* The Singularity (Black Hole) */}
            <div className="absolute rounded-full bg-black z-10"
                 style={{
                    width: `${horizonRadiusPercent}%`,
                    height: `${horizonRadiusPercent}%`,
                    boxShadow: `0 0 20px ${coreColor}`
                 }}
            />

            <svg viewBox="0 0 200 200" className="absolute inset-0 w-full h-full z-0 pointer-events-none">
                <defs>
                    <filter id="tunnel-glow">
                        <feGaussianBlur stdDeviation="1.5" result="coloredBlur"/>
                        <feMerge>
                            <feMergeNode in="coloredBlur"/>
                            <feMergeNode in="SourceGraphic"/>
                        </feMerge>
                    </filter>
                    <mask id="horizon-mask">
                        <rect x="0" y="0" width="200" height="200" fill="white" />
                        <circle cx="100" cy="100" r={horizonRadiusPercent} fill="black" /> 
                        {/* Note: SVG units for mask need to match viewbox roughly. % in React style vs SVG units. 
                            Let's approximate horizonRadiusPercent to SVG units (200 width -> 100 radius = 50%) */}
                    </mask>
                </defs>

                {rings.map(ring => {
                    // Perspective projection logic
                    // Z goes 0 (Near) -> 1 (Far/Horizon)

                    // Max radius is corner of the box (approx 141 for 200x200), let's say 120 for visibility
                    const maxRadius = 140; 

                    // The radius at the horizon
                    // Convert percent to approx SVG units (200px viewbox width = 100% -> 2 units per %)
                    // Radius of 100% width is 100 units.
                    const minRadius = horizonRadiusPercent * 1.5; 

                    // Linear interpolation of radius based on Z
                    // r = max - (max - min) * z
                    const currentRadius = maxRadius - (maxRadius - minRadius) * ring.z;

                    // Opacity fades in as it spawns, fades out as it hits horizon
                    // Fade in quickly (0 to 0.1), Fade out near horizon (0.9 to 1.0)
                    let opacity = 1;
                    if (ring.z < 0.2) opacity = ring.z * 5;
                    if (ring.z > 0.8) opacity = (1 - ring.z) * 5;

                    // Boost opacity with audio
                    opacity = Math.min(1, opacity * (0.3 + audioImpact));

                    const strokeWidth = (1 - ring.z) * 2 + 0.5;

                    // Dash array calculation for "segmented" look
                    // Circumference = 2 * PI * r
                    const c = 2 * Math.PI * currentRadius;
                    const dashLen = c / (ring.segments * 2);

                    return (
                        <g key={ring.id} transform={`rotate(${ring.rotation} 100 100)`}>
                            <circle 
                                cx="100" cy="100" r={Math.max(0, currentRadius)}
                                fill="none"
                                stroke={gridColor}
                                strokeWidth={strokeWidth}
                                strokeOpacity={opacity}
                                strokeDasharray={`${dashLen} ${dashLen}`}
                                style={{ filter: 'url(#tunnel-glow)' }}
                            />
                        </g>
                    );
                })}
            </svg>
        </div>
    );
};

