import React, { useMemo } from 'react';
import { PluginContainer } from '../shared/PluginContainer';
import { Knob } from '../shared/Knob';
import { MixxEntangleSettings, PluginComponentProps, AudioSignal, GlobalSettings } from '../../types';
import { PrimeBrainStub } from '../../lib/PrimeBrainStub';
import { VstBridge, VisualizerData } from '../../vst/VstBridge';
import { useVstBridge } from '../../vst/useVstBridge';
import { mapRange } from '../../lib/utils';

interface Qubit {
    id: number;
    angle: number;
    radius: number;
    speed: number;
}

interface EntangleVisualizerData extends VisualizerData {
    qubitA: Qubit[];
    qubitB: Qubit[];
    beamOpacity: number;
    jitterAmount: number;
    blurAmount: number;
    rotationA: number;
    rotationB: number;
}

class MixxEntangleVstBridge extends VstBridge<MixxEntangleSettings> {
    private rotationA = 0;
    private rotationB = 0;

    constructor(initialSettings: MixxEntangleSettings) {
        super(initialSettings);
    }

    public dspProcess(
        audioSignal: AudioSignal,
        width: number,
        height: number,
        globalSettings: GlobalSettings
    ): EntangleVisualizerData {
        const { linkage, uncertainty, observation, mix } = this.settings;

        const animationSpeedMultiplier = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 2.0);

        // Update rotations
        const baseSpeed = 0.5 * animationSpeedMultiplier;
        const audioBoost = (audioSignal.level / 100) * 2;

        this.rotationA += baseSpeed + audioBoost;
        // Ring B rotation depends on Linkage. High linkage = synced rotation. Low linkage = chaotic/offset.
        const linkageFactor = linkage / 100;
        this.rotationB += (baseSpeed + audioBoost) * (0.5 + linkageFactor * 0.5) + (1 - linkageFactor) * Math.sin(Date.now() / 1000);

        const numParticles = 12;
        const qubitA = Array.from({ length: numParticles }).map((_, i) => ({
            id: i,
            angle: (i / numParticles) * 360,
            radius: 40,
            speed: 1
        }));

        // Qubit B mirrors A but with offset based on linkage
        const qubitB = qubitA.map(p => ({
            ...p,
            angle: p.angle + (1 - linkageFactor) * 180 // 180 deg offset at 0 linkage, 0 offset at 100 linkage
        }));

        const uncertaintyJitter = (uncertainty / 100) * 10;
        const blurAmount = (100 - observation) / 100 * 10; // High observation = low blur

        return {
            qubitA,
            qubitB,
            beamOpacity: linkageFactor * (mix / 100),
            jitterAmount: uncertaintyJitter,
            blurAmount,
            rotationA: this.rotationA,
            rotationB: this.rotationB
        };
    }
}

const EntangleVisualizer: React.FC<{ data: EntangleVisualizerData | null }> = ({ data }) => {
    if (!data) return <div className="w-full h-full bg-black/20" />;
    const { qubitA, qubitB, beamOpacity, jitterAmount, blurAmount, rotationA, rotationB } = data;

    const renderRing = (qubits: Qubit[], rotation: number, offsetX: number, color: string) => (
        <div className="absolute top-1/2 left-1/2 w-32 h-32 -ml-16 -mt-16 transition-transform" 
             style={{ transform: `translate(${offsetX}px, -50%) rotate(${rotation}deg)` }}>
            {qubits.map(q => (
                <div key={q.id} className="absolute w-2 h-2 rounded-full"
                    style={{
                        backgroundColor: color,
                        top: '50%',
                        left: '50%',
                        transform: `
                            rotate(${q.angle}deg) 
                            translate(${q.radius}px) 
                            rotate(-${q.angle}deg)
                            translate(${Math.random() * jitterAmount}px, ${Math.random() * jitterAmount}px)
                        `,
                        filter: `blur(${blurAmount}px)`,
                        boxShadow: `0 0 ${5 + blurAmount}px ${color}`
                    }}
                />
            ))}
            <div className="absolute inset-0 rounded-full border border-white/10" />
        </div>
    );

    return (
        <div className="relative w-full h-full flex items-center justify-center overflow-hidden bg-black/40 rounded-lg border border-indigo-500/20">
            {/* Entanglement Beam - Connecting the two centers (-80px and +80px) */}
            <div className="absolute top-1/2 left-1/2 w-[160px] h-1 -ml-[80px] -mt-0.5 bg-indigo-400 blur-md transition-opacity" 
                 style={{ opacity: beamOpacity }} />

            <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ opacity: beamOpacity }}>
                {/* Line from center-80 to center+80 */}
                <line x1="calc(50% - 80px)" y1="50%" x2="calc(50% + 80px)" y2="50%" stroke="white" strokeWidth="1" strokeDasharray="4 4" className="animate-pulse" />
            </svg>

            {/* Qubit A (Left) */}
            {renderRing(qubitA, rotationA, -80, '#818cf8')}

            {/* Qubit B (Right) */}
            {renderRing(qubitB, rotationB, 80, '#c084fc')}
        </div>
    );
};

export const MixxEntangle: React.FC<PluginComponentProps<MixxEntangleSettings>> = ({ 
    isDragging, isResizing, name, description, pluginState, setPluginState, isLearning, onMidiLearn, onClose, globalSettings, audioSignal
}) => {
    const { linkage, uncertainty, observation, mix, output } = pluginState;

    const { visualizerData } = useVstBridge(
        pluginState,
        audioSignal,
        globalSettings,
        (initialState) => new MixxEntangleVstBridge(initialState)
    );

    const handleValueChange = (param: keyof MixxEntangleSettings, value: number) => {
        setPluginState(prevState => ({ ...prevState, [param]: value }));
        PrimeBrainStub.sendEvent('parameter_change', { plugin: 'mixx-entangle', parameter: param, value });
    };

    return (
        <PluginContainer title={name} subtitle={description} isDragging={isDragging} isResizing={isResizing} onClose={onClose}>
            <div className="w-full h-full flex flex-col items-center justify-between gap-6 p-4">
                <div className="w-full flex-1">
                    <EntangleVisualizer data={visualizerData as EntangleVisualizerData | null} />
                </div>
                <div className="flex flex-wrap justify-center gap-4">
                    <Knob label="Linkage" value={linkage} setValue={(v) => handleValueChange('linkage', v)} paramName="linkage" isLearning={isLearning('linkage')} onMidiLearn={onMidiLearn} />
                    <Knob label="Uncertainty" value={uncertainty} setValue={(v) => handleValueChange('uncertainty', v)} paramName="uncertainty" isLearning={isLearning('uncertainty')} onMidiLearn={onMidiLearn} />
                    <Knob label="Observation" value={observation} setValue={(v) => handleValueChange('observation', v)} paramName="observation" isLearning={isLearning('observation')} onMidiLearn={onMidiLearn} />
                    <Knob label="Mix" value={mix} setValue={(v) => handleValueChange('mix', v)} paramName="mix" isLearning={isLearning('mix')} onMidiLearn={onMidiLearn} />
                    <Knob label="Output" value={output} setValue={(v) => handleValueChange('output', v)} paramName="output" isLearning={isLearning('output')} onMidiLearn={onMidiLearn} />
                </div>
            </div>
        </PluginContainer>
    );
};

import React, { useMemo } from 'react';
import { PluginContainer } from '../shared/PluginContainer';
import { Knob } from '../shared/Knob';
import { MixxTunnelSettings, PluginComponentProps, AudioSignal, GlobalSettings } from '../../types';
import { PrimeBrainStub } from '../../lib/PrimeBrainStub';
import { VstBridge, VisualizerData } from '../../vst/VstBridge';
import { useVstBridge } from '../../vst/useVstBridge';
import { mapRange } from '../../lib/utils';

interface TunnelRing {
    id: number;
    z: number; // Depth position: 0 (near/face) to 1 (far/horizon)
    rotation: number;
    segments: number;
    speedOffset: number;
}

interface TunnelVisualizerData extends VisualizerData {
    rings: TunnelRing[];
    horizonRadiusPercent: number;
    coreColor: string;
    gridColor: string;
    audioImpact: number;
}

class MixxTunnelVstBridge extends VstBridge<MixxTunnelSettings> {
    private rings: TunnelRing[] = [];
    private ringIdCounter = 0;

    constructor(initialSettings: MixxTunnelSettings) {
        super(initialSettings);
        // Initialize pool with some pre-existing rings for immediate visuals
        for(let i=0; i<20; i++) {
            this.spawnRing(Math.random());
        }
        this.rings.sort((a, b) => b.z - a.z);
    }

    private spawnRing(startZ: number = 0) {
        this.rings.push({
            id: this.ringIdCounter++,
            z: startZ,
            rotation: Math.random() * 360,
            segments: Math.floor(Math.random() * 3) + 3, // 3 to 5 segments
            speedOffset: 0.8 + Math.random() * 0.4
        });
    }

    public dspProcess(
        audioSignal: AudioSignal,
        width: number,
        height: number,
        globalSettings: GlobalSettings
    ): TunnelVisualizerData {
        const { length, gravity, horizon, mix } = this.settings;

        // Simulation constants
        const animationSpeedMultiplier = mapRange(globalSettings.animationIntensity, 0, 100, 0.5, 2.0);

        // Length controls traversal speed (Longer = Slower)
        // Range: Fast (0) to Slow (100)
        const baseSpeed = (0.02 - (length / 100) * 0.018) * animationSpeedMultiplier;

        // Gravity controls acceleration curve towards z=1
        const gravityFactor = 1 + (gravity / 100) * 3; 

        // Horizon controls the visual size of the center
        const horizonRadiusPercent = 5 + (horizon / 100) * 20;

        // Audio reactivity
        const audioImpact = (audioSignal.level / 100) * (mix / 100);
        const rotationSpeed = 0.5 + audioImpact * 5;

        // Update rings
        const activeRings: TunnelRing[] = [];

        this.rings.forEach(ring => {
            // Non-linear movement: speed increases as z approaches 1 based on gravity
            const currentSpeed = baseSpeed * Math.pow(1 + ring.z, gravityFactor - 1);
            ring.z += currentSpeed * ring.speedOffset;

            // Rotation
            ring.rotation += rotationSpeed;

            if (ring.z < 1) {
                activeRings.push(ring);
            }
        });

        this.rings = activeRings;

        // Spawn new rings to maintain density based on length
        const gapThreshold = baseSpeed * 10; 

        // Sort by Z (Farthest first for painter's algo if needed, though we use stroke)
        this.rings.sort((a, b) => b.z - a.z);

        const nearestRing = this.rings[this.rings.length - 1]; // Ring with lowest Z
        if (!nearestRing || nearestRing.z > gapThreshold) {
             this.spawnRing(0);
        }

        const hue = 260; // Deep Indigo/Purple
        const coreColor = `hsl(${hue}, 80%, ${5 + audioImpact * 40}%)`;
        const gridColor = `hsl(${hue - 40}, 90%, ${60 + audioImpact * 20}%)`;

        return {
            rings: this.rings,
            horizonRadiusPercent,
            coreColor,
            gridColor,
            audioImpact
        };
    }
}

const TunnelVisualizer: React.FC<{ data: TunnelVisualizerData | null }> = ({ data }) => {
    if (!data) return <div className="w-full h-full bg-black/20" />;
    const { rings, horizonRadiusPercent, coreColor, gridColor, audioImpact } = data;

    return (
        <div className="relative w-full h-full flex items-center justify-center bg-black/40 rounded-lg overflow-hidden border border-indigo-500/20 shadow-[inset_0_0_50px_rgba(0,0,0,0.8)]">

            {/* Event Horizon (Center Glow) */}
            <div className="absolute rounded-full blur-2xl" 
                style={{
                    width: `${horizonRadiusPercent * 2.5}%`,
                    height: `${horizonRadiusPercent * 2.5}%`,
                    background: coreColor,
                    opacity: 0.8
                }} 
            />
            {/* The Void */}
            <div className="absolute rounded-full bg-black z-10"
                 style={{
                    width: `${horizonRadiusPercent}%`,
                    height: `${horizonRadiusPercent}%`,
                    boxShadow: `0 0 20px ${coreColor}`
                 }}
            />

            <svg viewBox="0 0 200 200" className="absolute inset-0 w-full h-full z-0 pointer-events-none">
                <defs>
                    <filter id="tunnel-glow">
                        <feGaussianBlur stdDeviation="1" result="coloredBlur"/>
                        <feMerge>
                            <feMergeNode in="coloredBlur"/>
                            <feMergeNode in="SourceGraphic"/>
                        </feMerge>
                    </filter>
                </defs>
                {rings.map(ring => {
                    const maxRadius = 140; 
                    const minRadius = horizonRadiusPercent; 

                    // Linear interpolation for radius
                    const currentRadius = maxRadius - (maxRadius - minRadius) * ring.z;

                    // Opacity Logic: Fade in at edges, bright in middle, fade slightly near horizon
                    let opacity = 0;
                    if (ring.z < 0.2) opacity = ring.z * 5;
                    else opacity = 1 - Math.pow(ring.z, 4) * 0.5; // Stay visible until very end

                    const strokeWidth = 0.5 + (1 - ring.z) * 1.5;

                    // Calculate dash array based on circumference to keep segment count consistent
                    const circumference = 2 * Math.PI * currentRadius;
                    const segmentLength = circumference / (ring.segments * 2);

                    return (
                        <g key={ring.id} transform={`rotate(${ring.rotation} 100 100)`}>
                            <circle 
                                cx="100" cy="100" r={Math.max(0, currentRadius)}
                                fill="none"
                                stroke={gridColor}
                                strokeWidth={strokeWidth}
                                strokeOpacity={opacity}
                                strokeDasharray={`${segmentLength} ${segmentLength}`}
                                style={{ filter: 'url(#tunnel-glow)' }}
                            />
                        </g>
                    );
                })}
            </svg>
        </div>
    );
};

